"""
Question bank generator — 500 curated AWS Cloud Practitioner exam questions.
Run this script to regenerate questions.json.
"""
import json, os
from collections import Counter

questions = []

# ══════════════════════════════════════════════════════════════════════════════
# CLOUD CONCEPTS — Difficulty 1
# ══════════════════════════════════════════════════════════════════════════════
questions += [
  {"question_text":"What does 'elasticity' mean in cloud computing?","options":["The ability to resize servers permanently","The ability to scale resources up or down automatically based on demand","The ability to move data between regions","The ability to encrypt data at rest"],"correct_answer":"The ability to scale resources up or down automatically based on demand","explanation":"Elasticity means the cloud can automatically provision and de-provision resources to match current demand, avoiding over-provisioning or under-provisioning.","memory_technique":"Elastic band — stretches when you need more, shrinks when you don't.","topic_area":"Cloud Concepts","difficulty_level":1,"it_context_mapping":"Traditional IT required buying peak capacity upfront. Elasticity replaces that with automatic scaling, like a staffing agency that adds or removes workers based on workload."},
  {"question_text":"Which of the following is a key advantage of cloud computing over traditional on-premises IT?","options":["Higher upfront capital costs","Ability to go global in minutes","Requires more staff to manage","Fixed capacity that cannot change"],"correct_answer":"Ability to go global in minutes","explanation":"Cloud providers have infrastructure in regions worldwide. You can deploy your application globally in minutes rather than months of procurement and setup.","memory_technique":"Cloud = instant global reach. On-premises = months of shipping and racking servers.","topic_area":"Cloud Concepts","difficulty_level":1,"it_context_mapping":"Deploying to a new country traditionally required leasing data center space, shipping hardware, and hiring local staff. AWS lets you launch in a new region with a few clicks."},
  {"question_text":"What is the primary benefit of 'pay-as-you-go' cloud pricing?","options":["You pay a fixed monthly fee regardless of usage","You pay only for the resources you actually consume","You must commit to a 3-year contract","You receive a dedicated server at no cost"],"correct_answer":"You pay only for the resources you actually consume","explanation":"Pay-as-you-go means you are billed only for what you use — compute seconds, storage gigabytes, data transferred — with no idle costs.","memory_technique":"Like a utility bill — you pay for the electricity you use, not for the capacity of the grid.","topic_area":"Cloud Concepts","difficulty_level":1,"it_context_mapping":"Traditional IT required paying for servers whether they were busy or idle. Pay-as-you-go eliminates wasted spend on unused capacity."},
  {"question_text":"What are the three cloud deployment models?","options":["Public, Private, Hybrid","On-premises, Colocation, Cloud","IaaS, PaaS, SaaS","Development, Staging, Production"],"correct_answer":"Public, Private, Hybrid","explanation":"Public cloud resources are owned and operated by a third-party provider. Private cloud is dedicated to one organisation. Hybrid combines both.","memory_technique":"PPH — Public, Private, Hybrid. Like housing: apartment (public), owned home (private), or both (hybrid).","topic_area":"Cloud Concepts","difficulty_level":1,"it_context_mapping":"Most enterprises use hybrid cloud — keeping sensitive workloads on-premises while using public cloud for scalable or less sensitive workloads."},
  {"question_text":"What does IaaS stand for?","options":["Internet as a Service","Infrastructure as a Service","Integration as a Service","Intelligence as a Service"],"correct_answer":"Infrastructure as a Service","explanation":"IaaS provides virtualised computing resources over the internet — servers, storage, and networking — that you manage yourself. Amazon EC2 is an example.","memory_technique":"IaaS = I am a Server. You get the raw infrastructure and manage everything above the hypervisor.","topic_area":"Cloud Concepts","difficulty_level":1,"it_context_mapping":"IaaS is equivalent to renting rack space in a colocation facility, but virtualised. You manage the OS and above; the provider manages the physical hardware."},
  {"question_text":"What does SaaS stand for?","options":["Storage as a Service","Software as a Service","Security as a Service","Serverless as a Service"],"correct_answer":"Software as a Service","explanation":"SaaS delivers fully managed software applications over the internet. The provider manages everything — infrastructure, OS, middleware, and the application itself.","memory_technique":"SaaS = Someone else's App Service. You just use the software; someone else runs it.","topic_area":"Cloud Concepts","difficulty_level":1,"it_context_mapping":"SaaS replaces installed software. Instead of installing Microsoft Office on every PC, you use Microsoft 365 in a browser — the same shift from on-premises apps to cloud-hosted ones."},
  {"question_text":"Which AWS support plan is included at no additional cost for all AWS accounts?","options":["Developer","Business","Enterprise","Basic"],"correct_answer":"Basic","explanation":"The Basic support plan is free for all AWS accounts. It includes access to documentation, whitepapers, AWS Trusted Advisor (limited checks), and the AWS Health Dashboard.","memory_technique":"Basic = free baseline. Everyone gets it automatically when they create an AWS account.","topic_area":"Cloud Concepts","difficulty_level":1,"it_context_mapping":"Basic support is like the free tier of a software product — enough to get started, but you pay more for faster response times and dedicated support engineers."},
  {"question_text":"What is an AWS Region?","options":["A single data center","A collection of edge locations","A geographic area containing multiple Availability Zones","A virtual private network segment"],"correct_answer":"A geographic area containing multiple Availability Zones","explanation":"An AWS Region is a physical location in the world containing multiple Availability Zones. Each Region is completely independent, providing fault isolation.","memory_technique":"Region = Country. AZ = City within that country. Multiple cities make a country.","topic_area":"Cloud Concepts","difficulty_level":1,"it_context_mapping":"Regions are equivalent to separate data center campuses in different cities. Traditional DR required owning or leasing space in a second location; AWS provides this globally."},
  {"question_text":"What is the AWS global network of edge locations used for?","options":["Running EC2 instances","Storing relational databases","Delivering content with low latency via CloudFront","Managing IAM users"],"correct_answer":"Delivering content with low latency via CloudFront","explanation":"AWS edge locations are part of the CloudFront CDN network. They cache content close to end users, reducing latency by serving requests from the nearest edge location.","memory_technique":"Edge = at the edge of the network, closest to users. Like a local warehouse vs. a central distribution center.","topic_area":"Cloud Concepts","difficulty_level":1,"it_context_mapping":"Edge locations are equivalent to CDN PoPs (Points of Presence) used by Akamai or Cloudflare — distributed caching nodes that reduce round-trip time for users."},
  {"question_text":"Which of the following best describes 'high availability' in AWS?","options":["A system that never fails","A system designed to minimise downtime through redundancy","A system that runs on a single powerful server","A system that only runs during business hours"],"correct_answer":"A system designed to minimise downtime through redundancy","explanation":"High availability means designing systems with redundancy so that if one component fails, another takes over automatically, minimising downtime.","memory_technique":"HA = Hardly Any downtime. Redundancy is the key — multiple components so one failure doesn't stop everything.","topic_area":"Cloud Concepts","difficulty_level":1,"it_context_mapping":"Traditional HA required expensive redundant hardware in separate data centers. AWS provides HA through multi-AZ deployments at a fraction of the cost."},
  {"question_text":"What is 'fault tolerance' in cloud computing?","options":["The ability to detect faults in code","The ability of a system to continue operating even when components fail","The maximum number of errors a system can log","The process of testing systems for bugs"],"correct_answer":"The ability of a system to continue operating even when components fail","explanation":"Fault tolerance means a system continues to function correctly even when one or more of its components fail. It goes beyond high availability by ensuring zero downtime.","memory_technique":"Fault tolerant = tolerates faults without stopping. Like a car that keeps driving even with a flat tyre (run-flat tyres).","topic_area":"Cloud Concepts","difficulty_level":1,"it_context_mapping":"Fault tolerance in traditional IT required expensive active-active configurations. AWS services like S3 and DynamoDB are built with fault tolerance by design."},
  {"question_text":"What does 'scalability' mean in the context of AWS?","options":["The ability to encrypt data","The ability to increase or decrease resources to handle changing workloads","The ability to monitor application performance","The ability to back up data automatically"],"correct_answer":"The ability to increase or decrease resources to handle changing workloads","explanation":"Scalability is the ability to handle growing or shrinking workloads by adding or removing resources. AWS supports both vertical scaling (bigger instances) and horizontal scaling (more instances).","memory_technique":"Scale = like a scale that adjusts to weight. Add more capacity when load increases, reduce when it decreases.","topic_area":"Cloud Concepts","difficulty_level":1,"it_context_mapping":"Traditional IT scaled by buying bigger servers (vertical) or adding more servers (horizontal). AWS makes both types of scaling fast and cost-effective."},
  {"question_text":"Which of the following is NOT one of the six advantages of cloud computing defined by AWS?","options":["Trade capital expense for variable expense","Benefit from massive economies of scale","Stop guessing capacity","Eliminate the need for internet connectivity"],"correct_answer":"Eliminate the need for internet connectivity","explanation":"The six advantages of cloud computing are: trade CapEx for OpEx, benefit from economies of scale, stop guessing capacity, increase speed and agility, stop spending money on data centers, and go global in minutes. Internet connectivity is required, not eliminated.","memory_technique":"The six advantages all make cloud BETTER. Eliminating internet would make it impossible — that's the giveaway.","topic_area":"Cloud Concepts","difficulty_level":1,"it_context_mapping":"These six advantages represent the core business case for cloud migration that AWS uses in its customer conversations."},
]

# ══════════════════════════════════════════════════════════════════════════════
# SECURITY AND COMPLIANCE — Difficulty 1
# ══════════════════════════════════════════════════════════════════════════════
questions += [
  {"question_text":"What is AWS IAM used for?","options":["Managing network traffic","Managing user access and permissions to AWS services","Monitoring application performance","Storing encryption keys"],"correct_answer":"Managing user access and permissions to AWS services","explanation":"AWS Identity and Access Management (IAM) enables you to manage access to AWS services and resources. You create users, groups, roles, and policies to control who can do what.","memory_technique":"IAM = I AM who I say I am. Controls identity and what each identity can do.","topic_area":"Security and Compliance","difficulty_level":1,"it_context_mapping":"IAM is equivalent to Active Directory — it manages who can access what resources and with what permissions."},
  {"question_text":"What is the root account in AWS?","options":["The first IAM user created","The account created when you first sign up for AWS with full unrestricted access","A read-only administrative account","An account used only for billing"],"correct_answer":"The account created when you first sign up for AWS with full unrestricted access","explanation":"The root account is created when you first sign up for AWS. It has complete access to all AWS services and resources. AWS strongly recommends not using the root account for everyday tasks.","memory_technique":"Root = the root of a tree — everything branches from it. Powerful but dangerous to use directly.","topic_area":"Security and Compliance","difficulty_level":1,"it_context_mapping":"The root account is like the local Administrator account on Windows — it has unrestricted access and should be locked away, with day-to-day work done through less privileged accounts."},
  {"question_text":"What is Multi-Factor Authentication (MFA)?","options":["A method of encrypting data with multiple keys","A security mechanism requiring two or more verification factors to authenticate","A way to share credentials between multiple users","A type of firewall rule"],"correct_answer":"A security mechanism requiring two or more verification factors to authenticate","explanation":"MFA adds an extra layer of security by requiring users to provide two or more verification factors: something they know (password) and something they have (MFA device or app).","memory_technique":"MFA = More Factors = More Assurance. Password alone is one lock; MFA adds a deadbolt.","topic_area":"Security and Compliance","difficulty_level":1,"it_context_mapping":"MFA is the same concept used in corporate VPNs with RSA SecurID tokens or Duo Security — a second factor prevents credential theft from being sufficient for access."},
  {"question_text":"What does the principle of least privilege mean?","options":["Giving users the maximum permissions they might ever need","Granting only the minimum permissions required to perform a task","Sharing a single admin account among all users","Allowing all users to access all resources by default"],"correct_answer":"Granting only the minimum permissions required to perform a task","explanation":"Least privilege means users and services should only have the permissions they need to do their job — nothing more. This limits the blast radius if credentials are compromised.","memory_technique":"Least privilege = least risk. Give the minimum keys needed — a janitor gets a building key, not a master key to every room.","topic_area":"Security and Compliance","difficulty_level":1,"it_context_mapping":"This mirrors RBAC (Role-Based Access Control) in traditional IT — users only get access to the systems and data their job requires."},
  {"question_text":"Which AWS service records API calls made in your AWS account for auditing?","options":["Amazon CloudWatch","AWS CloudTrail","AWS Config","Amazon Inspector"],"correct_answer":"AWS CloudTrail","explanation":"AWS CloudTrail records API calls made in your AWS account, including the identity of the caller, time, source IP, and request/response elements. It is the primary audit log for AWS.","memory_technique":"CloudTrail = Cloud Paper Trail. Every API call leaves a trail of breadcrumbs you can follow.","topic_area":"Security and Compliance","difficulty_level":1,"it_context_mapping":"CloudTrail is equivalent to SIEM audit logging — it records who did what, when, and from where, just like Splunk or ArcSight in traditional IT."},
  {"question_text":"What is an IAM policy?","options":["A document that defines permissions for AWS resources","A type of EC2 instance","A network firewall rule","A billing alert"],"correct_answer":"A document that defines permissions for AWS resources","explanation":"An IAM policy is a JSON document that defines what actions are allowed or denied on which AWS resources. Policies are attached to users, groups, or roles.","memory_technique":"Policy = rules document. Like a company policy that says what employees can and cannot do.","topic_area":"Security and Compliance","difficulty_level":1,"it_context_mapping":"IAM policies are equivalent to ACLs (Access Control Lists) or Group Policy Objects in Active Directory — they define what actions are permitted on which resources."},
  {"question_text":"What is AWS Shield Standard?","options":["A paid DDoS protection service","Free DDoS protection automatically applied to all AWS accounts","A web application firewall","An intrusion detection system"],"correct_answer":"Free DDoS protection automatically applied to all AWS accounts","explanation":"AWS Shield Standard is automatically enabled for all AWS customers at no extra charge. It provides protection against common network and transport layer DDoS attacks.","memory_technique":"Shield Standard = free armour that comes with your AWS account. No setup required.","topic_area":"Security and Compliance","difficulty_level":1,"it_context_mapping":"Shield Standard is like the basic DDoS mitigation that ISPs provide — it's always on and protects against volumetric attacks without any configuration."},
  {"question_text":"Which AWS service helps protect web applications from common exploits like SQL injection?","options":["AWS Shield","AWS WAF","Amazon GuardDuty","AWS Config"],"correct_answer":"AWS WAF","explanation":"AWS WAF (Web Application Firewall) protects web applications from common web exploits. You can create rules to block SQL injection, cross-site scripting, and other attack patterns.","memory_technique":"WAF = Web Application Filter. It filters bad web traffic before it reaches your app.","topic_area":"Security and Compliance","difficulty_level":1,"it_context_mapping":"AWS WAF is equivalent to traditional WAF appliances like F5 ASM or Imperva — it inspects HTTP/HTTPS traffic and blocks malicious requests based on rules."},
  {"question_text":"What is encryption at rest?","options":["Encrypting data while it is being transmitted over a network","Encrypting data while it is stored on disk","Encrypting data only during processing","Encrypting data before it is created"],"correct_answer":"Encrypting data while it is stored on disk","explanation":"Encryption at rest protects data stored on disk or in databases. If physical media is stolen or accessed without authorisation, the data remains unreadable without the encryption key.","memory_technique":"At rest = sitting still (stored). Encrypt the data while it's sitting on disk.","topic_area":"Security and Compliance","difficulty_level":1,"it_context_mapping":"Encryption at rest is the same concept used for BitLocker on Windows laptops or TDE (Transparent Data Encryption) on SQL Server — protecting stored data from physical theft."},
  {"question_text":"What is encryption in transit?","options":["Encrypting data while it is stored on disk","Encrypting data while it is being transmitted over a network","Encrypting data at the application layer only","Encrypting backup files"],"correct_answer":"Encrypting data while it is being transmitted over a network","explanation":"Encryption in transit protects data as it moves between systems. HTTPS/TLS is the most common example — it encrypts data between a browser and a web server.","memory_technique":"In transit = moving. Encrypt the data while it's travelling, like an armoured truck for data.","topic_area":"Security and Compliance","difficulty_level":1,"it_context_mapping":"Encryption in transit is equivalent to using SSL/TLS on web servers or IPSec VPN tunnels — protecting data from interception while it travels across networks."},
  {"question_text":"What does AWS Artifact provide?","options":["Automated security scanning","On-demand access to AWS compliance reports and agreements","Real-time threat detection","Network traffic analysis"],"correct_answer":"On-demand access to AWS compliance reports and agreements","explanation":"AWS Artifact is a self-service portal for on-demand access to AWS compliance documentation, including SOC reports, PCI DSS reports, and ISO certifications.","memory_technique":"Artifact = official document. AWS Artifact = official compliance documents from AWS.","topic_area":"Security and Compliance","difficulty_level":1,"it_context_mapping":"AWS Artifact replaces the process of requesting compliance reports from your cloud provider via email or account manager — you can download them instantly."},
  {"question_text":"Which AWS service provides a managed firewall to protect your VPC?","options":["AWS WAF","Security Groups","AWS Network Firewall","Amazon Inspector"],"correct_answer":"AWS Network Firewall","explanation":"AWS Network Firewall is a managed network firewall service for VPCs. It provides stateful inspection, intrusion prevention, and web filtering at the network level.","memory_technique":"Network Firewall = firewall for your VPC network. Like a traditional perimeter firewall but managed by AWS.","topic_area":"Security and Compliance","difficulty_level":1,"it_context_mapping":"AWS Network Firewall replaces traditional perimeter firewall appliances (Cisco ASA, Palo Alto) that sit at the edge of a data center network."},
]

# ══════════════════════════════════════════════════════════════════════════════
# TECHNOLOGY — Difficulty 1
# ══════════════════════════════════════════════════════════════════════════════
questions += [
  {"question_text":"What is Amazon EC2?","options":["A managed database service","A virtual server in the cloud","A content delivery network","A serverless compute service"],"correct_answer":"A virtual server in the cloud","explanation":"Amazon EC2 (Elastic Compute Cloud) provides resizable virtual servers (instances) in the cloud. You choose the CPU, memory, storage, and networking configuration.","memory_technique":"EC2 = Elastic Cloud Computer. A virtual machine you can resize running in the cloud.","topic_area":"Technology","difficulty_level":1,"it_context_mapping":"EC2 is equivalent to a virtual machine on VMware or Hyper-V, but hosted by AWS. You manage the OS and above; AWS manages the hypervisor and hardware."},
  {"question_text":"What is Amazon S3 used for?","options":["Running virtual servers","Storing objects such as files and images","Managing DNS records","Sending emails"],"correct_answer":"Storing objects such as files and images","explanation":"Amazon S3 (Simple Storage Service) is object storage for the internet. You can store any type of file — images, videos, backups, logs — and access them via HTTP/HTTPS.","memory_technique":"S3 = Simple Storage Service. Three S's = three words. Store anything, anywhere, at any scale.","topic_area":"Technology","difficulty_level":1,"it_context_mapping":"S3 replaces traditional NAS/SAN file servers and tape backup systems. It's like a limitless network drive accessible from anywhere on the internet."},
  {"question_text":"What is AWS Lambda?","options":["A managed Kubernetes service","A serverless compute service that runs code in response to events","A relational database service","A content delivery network"],"correct_answer":"A serverless compute service that runs code in response to events","explanation":"AWS Lambda runs your code without you provisioning or managing servers. You upload your code, define triggers, and Lambda handles scaling, availability, and execution.","memory_technique":"Lambda = Zero to running in milliseconds, no maintenance required. Pay per invocation.","topic_area":"Technology","difficulty_level":1,"it_context_mapping":"Lambda replaces always-on application servers for event-driven workloads. Instead of a server waiting for requests, Lambda wakes up only when needed — like a contractor vs. a full-time employee."},
  {"question_text":"What is Amazon RDS?","options":["A NoSQL database service","A managed relational database service","A data warehouse service","An in-memory caching service"],"correct_answer":"A managed relational database service","explanation":"Amazon RDS (Relational Database Service) is a managed service for relational databases. It supports MySQL, PostgreSQL, MariaDB, Oracle, SQL Server, and Amazon Aurora.","memory_technique":"RDS = Relational Database Service. It manages the boring parts (patching, backups, failover) so you focus on your data.","topic_area":"Technology","difficulty_level":1,"it_context_mapping":"RDS replaces self-managed database servers. Instead of a DBA managing OS patches, backups, and replication, AWS handles all of that."},
  {"question_text":"What is Amazon VPC?","options":["A virtual private server","An isolated virtual network in the AWS cloud","A VPN service for connecting to on-premises","A content delivery network"],"correct_answer":"An isolated virtual network in the AWS cloud","explanation":"Amazon VPC (Virtual Private Cloud) lets you provision a logically isolated section of the AWS Cloud where you can launch resources in a virtual network you define.","memory_technique":"VPC = Virtual Private Cloud = Your own private neighbourhood in AWS. You control the streets (subnets) and gates (security groups).","topic_area":"Technology","difficulty_level":1,"it_context_mapping":"VPC is equivalent to a traditional VLAN or private network segment in a data center. You get the same network isolation and control, but in software."},
  {"question_text":"What is Amazon CloudFront?","options":["A DNS service","A content delivery network that caches content at edge locations","A load balancer","A VPN gateway"],"correct_answer":"A content delivery network that caches content at edge locations","explanation":"Amazon CloudFront is a CDN that delivers data, videos, applications, and APIs globally with low latency by caching content at edge locations close to users.","memory_technique":"CloudFront = Cloud at the Front (edge). Content moves to the front lines closest to users.","topic_area":"Technology","difficulty_level":1,"it_context_mapping":"CloudFront is equivalent to traditional CDN services like Akamai or Cloudflare. It caches content at edge nodes globally to accelerate web delivery."},
  {"question_text":"What is Amazon DynamoDB?","options":["A managed relational database","A managed NoSQL key-value and document database","A data warehouse","A graph database"],"correct_answer":"A managed NoSQL key-value and document database","explanation":"Amazon DynamoDB is a fully managed NoSQL database that delivers single-digit millisecond performance at any scale. It supports key-value and document data models.","memory_technique":"DynamoDB = Dynamic + DB. Flexible schema, fast performance at any scale.","topic_area":"Technology","difficulty_level":1,"it_context_mapping":"DynamoDB replaces self-managed NoSQL databases like MongoDB or Cassandra. AWS handles patching, scaling, and replication automatically."},
  {"question_text":"What is Elastic Load Balancing (ELB)?","options":["A service that automatically scales EC2 instances","A service that distributes incoming traffic across multiple targets","A DNS routing service","A firewall service"],"correct_answer":"A service that distributes incoming traffic across multiple targets","explanation":"Elastic Load Balancing automatically distributes incoming application traffic across multiple targets (EC2 instances, containers, IP addresses) to ensure no single target is overwhelmed.","memory_technique":"Load Balancer = traffic cop. Directs cars (requests) to different lanes (servers) to prevent jams.","topic_area":"Technology","difficulty_level":1,"it_context_mapping":"ELB replaces hardware load balancers like F5 BIG-IP or Citrix NetScaler. It provides the same traffic distribution without managing physical appliances."},
  {"question_text":"What is Amazon Route 53?","options":["A content delivery network","A scalable DNS and domain registration service","A load balancer","A VPN service"],"correct_answer":"A scalable DNS and domain registration service","explanation":"Amazon Route 53 is a highly available and scalable DNS web service. It translates domain names into IP addresses and supports domain registration and health checking.","memory_technique":"Route 53 = Road signs for the internet. Port 53 is the DNS port — Route 53 routes traffic using DNS.","topic_area":"Technology","difficulty_level":1,"it_context_mapping":"Route 53 replaces on-premises DNS servers (BIND, Windows DNS) and external DNS providers, adding cloud-native features like health-check-based failover."},
  {"question_text":"What is Amazon SNS?","options":["A message queue service","A pub/sub notification service that pushes messages to subscribers","A streaming data service","An email marketing service"],"correct_answer":"A pub/sub notification service that pushes messages to subscribers","explanation":"Amazon SNS (Simple Notification Service) is a pub/sub messaging service. Publishers send messages to topics, and SNS pushes them to all subscribers (email, SMS, Lambda, SQS, HTTP).","memory_technique":"SNS = Shout Notification Service. One publisher shouts to a topic; all subscribers hear it.","topic_area":"Technology","difficulty_level":1,"it_context_mapping":"SNS is equivalent to a publish-subscribe message broker like ActiveMQ topics or a corporate email distribution list — one message goes to many recipients."},
  {"question_text":"What is Amazon SQS?","options":["A pub/sub notification service","A fully managed message queue service","A streaming analytics service","A workflow orchestration service"],"correct_answer":"A fully managed message queue service","explanation":"Amazon SQS (Simple Queue Service) is a fully managed message queuing service that decouples application components. Producers send messages to a queue; consumers poll and process them independently.","memory_technique":"SQS = Super Queue Service. Like a post office — sender drops off mail, receiver picks up when ready.","topic_area":"Technology","difficulty_level":1,"it_context_mapping":"SQS replaces traditional message brokers like IBM MQ or RabbitMQ. It provides the same decoupling pattern without managing broker infrastructure."},
  {"question_text":"What is AWS Elastic Beanstalk?","options":["A container orchestration service","A platform as a service that deploys and manages web applications automatically","A serverless function service","A managed Kubernetes service"],"correct_answer":"A platform as a service that deploys and manages web applications automatically","explanation":"AWS Elastic Beanstalk is a PaaS that automatically handles deployment, capacity provisioning, load balancing, and monitoring. You upload your code and Beanstalk handles the rest.","memory_technique":"Beanstalk = magic beanstalk that grows your app automatically. Upload code, it handles everything else.","topic_area":"Technology","difficulty_level":1,"it_context_mapping":"Elastic Beanstalk is equivalent to Heroku or Google App Engine — a PaaS where you focus on code and the platform manages the infrastructure."},
  {"question_text":"What is Amazon EBS?","options":["Object storage for the internet","Block storage volumes that attach to EC2 instances","A file sharing service","A backup service"],"correct_answer":"Block storage volumes that attach to EC2 instances","explanation":"Amazon EBS (Elastic Block Store) provides persistent block storage volumes for EC2 instances. EBS volumes behave like raw, unformatted block devices that you can format and mount.","memory_technique":"EBS = External Block Storage. Like a virtual hard drive you plug into your EC2 instance.","topic_area":"Technology","difficulty_level":1,"it_context_mapping":"EBS is equivalent to a SAN (Storage Area Network) LUN attached to a server. It provides persistent block storage that survives instance stops and starts."},
]

