# ADDITIONAL QUESTIONS — Difficulty 2 (more coverage)
# ══════════════════════════════════════════════════════════════════════════════
questions += [
  {"question_text":"What is Amazon Cognito?","options":["A database service","A service for adding user sign-up, sign-in, and access control to web and mobile apps","A monitoring service","A content delivery service"],"correct_answer":"A service for adding user sign-up, sign-in, and access control to web and mobile apps","explanation":"Amazon Cognito provides authentication, authorisation, and user management for web and mobile apps. It supports social identity providers (Google, Facebook) and enterprise identity providers via SAML.","memory_technique":"Cognito = Cognitive (knows who you are). User pools for authentication, identity pools for AWS access.","topic_area":"Security and Compliance","difficulty_level":2,"it_context_mapping":"Cognito replaces custom authentication systems and integrates with existing identity providers — equivalent to using ADFS or Okta for application authentication."},
  {"question_text":"What is AWS Systems Manager?","options":["A service for managing AWS accounts","A unified interface for viewing and controlling AWS infrastructure, including patch management and run commands","A database management service","A network management service"],"correct_answer":"A unified interface for viewing and controlling AWS infrastructure, including patch management and run commands","explanation":"AWS Systems Manager provides a unified interface for operational data from multiple AWS services and automates operational tasks across AWS resources, including patch management, configuration, and run commands.","memory_technique":"Systems Manager = IT admin's Swiss Army knife. Patch, configure, run commands, and manage your fleet from one place.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"Systems Manager replaces traditional IT management tools like SCCM (Microsoft Endpoint Manager) or Ansible for managing server fleets — patching, configuration, and remote command execution."},
  {"question_text":"What is Amazon WorkSpaces?","options":["A project management tool","A managed desktop-as-a-service (DaaS) solution","A document collaboration service","A video conferencing service"],"correct_answer":"A managed desktop-as-a-service (DaaS) solution","explanation":"Amazon WorkSpaces is a managed, secure Desktop-as-a-Service (DaaS) solution. It allows you to provision cloud-based virtual desktops for users, accessible from any device.","memory_technique":"WorkSpaces = Work from anywhere. Virtual desktops in the cloud — your desktop follows you.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"WorkSpaces replaces traditional VDI (Virtual Desktop Infrastructure) solutions like Citrix or VMware Horizon. It provides the same virtual desktop experience without managing the underlying infrastructure."},
  {"question_text":"What is AWS OpsWorks?","options":["A CI/CD pipeline service","A configuration management service using Chef and Puppet","A monitoring service","A deployment service"],"correct_answer":"A configuration management service using Chef and Puppet","explanation":"AWS OpsWorks is a configuration management service that provides managed instances of Chef and Puppet. It automates server configuration, deployment, and management.","memory_technique":"OpsWorks = Operations automation. Uses Chef/Puppet to automate server configuration — like a robot sysadmin.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"OpsWorks is equivalent to managed Chef or Puppet — the same configuration management tools enterprises use, but with AWS managing the Chef/Puppet infrastructure."},
  {"question_text":"What is Amazon SES?","options":["A storage service","A managed email sending service","A security service","A streaming service"],"correct_answer":"A managed email sending service","explanation":"Amazon SES (Simple Email Service) is a cloud-based email sending service for transactional, marketing, and bulk email. It provides high deliverability and integrates with other AWS services.","memory_technique":"SES = Simple Email Service. Send emails at scale without managing mail servers.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"SES replaces self-managed SMTP servers and email delivery infrastructure. It's equivalent to using a managed email delivery service like SendGrid or Mailgun."},
  {"question_text":"What is Amazon Pinpoint?","options":["A GPS tracking service","A customer engagement service for sending targeted messages via email, SMS, push notifications, and voice","A network monitoring service","A data analytics service"],"correct_answer":"A customer engagement service for sending targeted messages via email, SMS, push notifications, and voice","explanation":"Amazon Pinpoint is a flexible and scalable outbound and inbound marketing communications service. It enables you to engage customers through multiple channels with targeted, personalised messages.","memory_technique":"Pinpoint = Pinpoint your customers. Target specific users with the right message on the right channel.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"Pinpoint replaces traditional marketing automation platforms for customer communications — similar to Salesforce Marketing Cloud or HubSpot but integrated with AWS."},
  {"question_text":"What is AWS Batch?","options":["A service for processing data in real time","A fully managed batch computing service for running batch jobs at any scale","A message queue service","A workflow orchestration service"],"correct_answer":"A fully managed batch computing service for running batch jobs at any scale","explanation":"AWS Batch enables developers to run batch computing workloads on AWS. It dynamically provisions the optimal quantity and type of compute resources based on the volume and requirements of the batch jobs.","memory_technique":"AWS Batch = Batch job manager. Submit jobs, AWS figures out the compute. Like a job scheduler that also provisions the servers.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"AWS Batch replaces traditional HPC job schedulers like PBS, LSF, or SLURM. It provides the same job queuing and scheduling capabilities without managing the compute cluster."},
  {"question_text":"What is Amazon Comprehend?","options":["A translation service","A natural language processing service that finds insights and relationships in text","A speech recognition service","A document storage service"],"correct_answer":"A natural language processing service that finds insights and relationships in text","explanation":"Amazon Comprehend is a natural language processing (NLP) service that uses machine learning to find insights and relationships in text — including sentiment analysis, entity recognition, and key phrase extraction.","memory_technique":"Comprehend = Comprehend text. AI that reads and understands text — sentiment, entities, topics.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"Comprehend replaces custom NLP models and third-party text analytics services. It provides pre-trained ML models for common text analysis tasks without requiring ML expertise."},
  {"question_text":"What is Amazon Rekognition?","options":["A speech recognition service","A service that adds image and video analysis capabilities using deep learning","A document recognition service","A handwriting recognition service"],"correct_answer":"A service that adds image and video analysis capabilities using deep learning","explanation":"Amazon Rekognition makes it easy to add image and video analysis to your applications. It can identify objects, people, text, scenes, and activities in images and videos.","memory_technique":"Rekognition = Recognition. AI that recognises what's in images and videos — faces, objects, text, scenes.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"Rekognition replaces custom computer vision models. It provides pre-trained deep learning models for image analysis — equivalent to using a specialised computer vision API."},
  {"question_text":"What is Amazon Translate?","options":["A document conversion service","A neural machine translation service for translating text between languages","A speech-to-text service","A text-to-speech service"],"correct_answer":"A neural machine translation service for translating text between languages","explanation":"Amazon Translate is a neural machine translation service that delivers fast, high-quality, and affordable language translation. It supports dozens of languages and integrates with other AWS services.","memory_technique":"Translate = Translation service. Neural machine translation — like Google Translate but integrated with AWS.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"Amazon Translate replaces custom translation integrations and third-party translation APIs. It provides the same neural machine translation capabilities as a managed AWS service."},
  {"question_text":"What is Amazon Polly?","options":["A speech recognition service","A text-to-speech service that converts text into lifelike speech","A translation service","A natural language processing service"],"correct_answer":"A text-to-speech service that converts text into lifelike speech","explanation":"Amazon Polly is a text-to-speech service that uses deep learning to synthesise natural-sounding human speech. It supports dozens of voices across multiple languages.","memory_technique":"Polly = Polly wants a cracker (parrot). Polly reads text aloud — text-to-speech with natural voices.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"Amazon Polly replaces traditional TTS engines and third-party voice synthesis services. It provides high-quality neural TTS without managing speech synthesis infrastructure."},
  {"question_text":"What is Amazon Transcribe?","options":["A text-to-speech service","A speech-to-text service that converts audio to text","A translation service","A document processing service"],"correct_answer":"A speech-to-text service that converts audio to text","explanation":"Amazon Transcribe is an automatic speech recognition (ASR) service that makes it easy to add speech-to-text capability to applications. It can transcribe audio files or real-time audio streams.","memory_technique":"Transcribe = Transcription. Converts spoken words to written text — like a court reporter but automated.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"Amazon Transcribe replaces custom ASR models and third-party transcription services. It provides automatic speech recognition without requiring ML expertise."},
  {"question_text":"What is Amazon Lex?","options":["A text analysis service","A service for building conversational interfaces (chatbots) using voice and text","A translation service","A document processing service"],"correct_answer":"A service for building conversational interfaces (chatbots) using voice and text","explanation":"Amazon Lex is a service for building conversational interfaces into any application using voice and text. It uses the same deep learning technologies that power Amazon Alexa.","memory_technique":"Lex = Lexicon (language). Build chatbots with the same AI as Alexa — natural language understanding built in.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"Amazon Lex replaces custom chatbot frameworks and third-party conversational AI platforms. It provides NLU (Natural Language Understanding) and dialogue management without ML expertise."},
]

