# BATCH 2 — Difficulty 1 (fill to 60)
# ══════════════════════════════════════════════════════════════════════════════
questions += [
  {"question_text":"What is Amazon EC2 Auto Scaling?","options":["A service that automatically backs up EC2 instances","A service that automatically adjusts the number of EC2 instances based on demand","A service that automatically patches EC2 instances","A service that automatically migrates EC2 instances"],"correct_answer":"A service that automatically adjusts the number of EC2 instances based on demand","explanation":"EC2 Auto Scaling automatically adds or removes EC2 instances based on conditions you define, ensuring you have the right number of instances to handle the load.","memory_technique":"Auto Scaling = Automatic thermostat. Too hot (high load)? Add instances. Too cold? Remove them.","topic_area":"Technology","difficulty_level":1,"it_context_mapping":"Auto Scaling replaces manual capacity management — like a staffing agency that automatically adds or removes workers based on workload."},
  {"question_text":"What is an Amazon Machine Image (AMI)?","options":["A type of EC2 instance","A template containing the software configuration required to launch an EC2 instance","A monitoring dashboard","A network configuration template"],"correct_answer":"A template containing the software configuration required to launch an EC2 instance","explanation":"An AMI provides the information required to launch an EC2 instance — it includes the OS, application server, and applications. You can use AWS-provided AMIs or create your own.","memory_technique":"AMI = Amazon Machine Image = Blueprint for EC2. Like a VM template — stamp out identical instances from one image.","topic_area":"Technology","difficulty_level":1,"it_context_mapping":"AMIs are equivalent to VM templates in VMware or Hyper-V — a golden image you use to rapidly deploy identical servers."},
  {"question_text":"What is an EC2 instance type?","options":["The operating system running on EC2","A configuration of CPU, memory, storage, and networking capacity","The region where EC2 runs","The pricing model for EC2"],"correct_answer":"A configuration of CPU, memory, storage, and networking capacity","explanation":"EC2 instance types define the hardware configuration — CPU cores, memory, storage, and network performance. Different families are optimised for different workloads (compute, memory, storage, GPU).","memory_technique":"Instance type = Server spec sheet. t3.micro = tiny. c5.4xlarge = compute-optimised, 4x large.","topic_area":"Technology","difficulty_level":1,"it_context_mapping":"Instance types are equivalent to server SKUs — different hardware configurations optimised for different workloads, like choosing between a web server and a database server spec."},
  {"question_text":"What is Amazon S3 versioning?","options":["A feature that tracks changes to S3 bucket policies","A feature that keeps multiple versions of an object in the same bucket","A feature that versions S3 bucket names","A feature that tracks S3 API versions"],"correct_answer":"A feature that keeps multiple versions of an object in the same bucket","explanation":"S3 versioning keeps multiple variants of an object in the same bucket. It protects against accidental deletion or overwriting — you can restore previous versions of objects.","memory_technique":"S3 versioning = Time machine for files. Every version is saved — accidentally deleted? Restore the previous version.","topic_area":"Technology","difficulty_level":1,"it_context_mapping":"S3 versioning is equivalent to file versioning in SharePoint or Google Drive — every change creates a new version you can restore."},
  {"question_text":"What is the AWS Management Console?","options":["A command-line tool for managing AWS","A web-based interface for accessing and managing AWS services","A mobile app for monitoring AWS","A desktop application for deploying AWS resources"],"correct_answer":"A web-based interface for accessing and managing AWS services","explanation":"The AWS Management Console is a web-based interface that provides a graphical way to access and manage AWS services. It is one of three ways to interact with AWS (along with CLI and SDKs).","memory_technique":"Management Console = AWS's website dashboard. Point and click to manage your cloud.","topic_area":"Cloud Concepts","difficulty_level":1,"it_context_mapping":"The Management Console is equivalent to a web-based admin portal — like the vSphere Web Client for VMware or the Azure Portal for Microsoft Azure."},
  {"question_text":"What is the AWS CLI?","options":["A web-based interface for AWS","A command-line tool for interacting with AWS services","A mobile application for AWS","A graphical desktop tool for AWS"],"correct_answer":"A command-line tool for interacting with AWS services","explanation":"The AWS CLI (Command Line Interface) is a unified tool for managing AWS services from the command line. It allows you to automate AWS operations through scripts.","memory_technique":"CLI = Command Line Interface. Type commands to control AWS — like a remote control for your cloud.","topic_area":"Cloud Concepts","difficulty_level":1,"it_context_mapping":"The AWS CLI is equivalent to PowerShell for Azure or gcloud CLI for Google Cloud — a command-line tool for automating cloud operations."},
  {"question_text":"What is an AWS SDK?","options":["A type of EC2 instance","A set of libraries that allow developers to interact with AWS services from their application code","A security scanning tool","A deployment framework"],"correct_answer":"A set of libraries that allow developers to interact with AWS services from their application code","explanation":"AWS SDKs (Software Development Kits) provide language-specific APIs for interacting with AWS services. SDKs are available for Python, Java, JavaScript, .NET, Go, Ruby, and more.","memory_technique":"SDK = Software Developer's Kit. Pre-built code libraries so you don't have to write raw API calls.","topic_area":"Cloud Concepts","difficulty_level":1,"it_context_mapping":"AWS SDKs are equivalent to vendor client libraries — like the Azure SDK for .NET or the Google Cloud client libraries — pre-built code that handles authentication and API calls."},
  {"question_text":"What is Amazon CloudWatch used for?","options":["Storing files","Monitoring AWS resources and applications","Managing user access","Deploying applications"],"correct_answer":"Monitoring AWS resources and applications","explanation":"Amazon CloudWatch is a monitoring service for AWS resources and applications. It collects metrics, logs, and events, and allows you to set alarms and create dashboards.","memory_technique":"CloudWatch = Cloud Watchman. Monitors everything — metrics, logs, alarms, dashboards.","topic_area":"Technology","difficulty_level":1,"it_context_mapping":"CloudWatch replaces traditional monitoring tools like Nagios or Zabbix — it collects metrics and logs from AWS resources and alerts you when things go wrong."},
  {"question_text":"What is AWS IAM best practice regarding the root account?","options":["Use the root account for all daily tasks","Enable MFA on the root account and avoid using it for everyday tasks","Share root account credentials with the team","Delete the root account after creating IAM users"],"correct_answer":"Enable MFA on the root account and avoid using it for everyday tasks","explanation":"AWS best practice is to enable MFA on the root account, create individual IAM users for daily tasks, and only use the root account for tasks that specifically require it (like changing account settings).","memory_technique":"Root account = nuclear launch codes. Lock it away, enable MFA, only use in emergencies.","topic_area":"Security and Compliance","difficulty_level":1,"it_context_mapping":"This mirrors the best practice of locking away the local Administrator account on Windows servers — create named accounts for daily use and reserve the built-in admin for emergencies."},
  {"question_text":"What is the AWS global infrastructure composed of?","options":["Data centers only","Regions, Availability Zones, and Edge Locations","Servers and storage only","Virtual machines and containers"],"correct_answer":"Regions, Availability Zones, and Edge Locations","explanation":"AWS global infrastructure consists of Regions (geographic areas), Availability Zones (isolated data center clusters within regions), and Edge Locations (CDN endpoints for CloudFront).","memory_technique":"AWS infrastructure = Regions (countries) → AZs (cities) → Edge Locations (local post offices). Three tiers of global presence.","topic_area":"Cloud Concepts","difficulty_level":1,"it_context_mapping":"This three-tier structure mirrors traditional IT: regional data centers (Regions), redundant facilities within a region (AZs), and CDN PoPs (Edge Locations)."},
  {"question_text":"What does 'durability' mean in the context of Amazon S3?","options":["How fast data can be retrieved","The probability that data will not be lost over time","How many users can access data simultaneously","How quickly data can be uploaded"],"correct_answer":"The probability that data will not be lost over time","explanation":"S3 Standard provides 99.999999999% (11 nines) durability, meaning the probability of losing an object is extremely low. AWS achieves this by storing data redundantly across multiple facilities.","memory_technique":"Durability = Data survival rate. 11 nines = 0.000000001% chance of losing data. Essentially zero.","topic_area":"Technology","difficulty_level":1,"it_context_mapping":"Durability is equivalent to RAID reliability in traditional storage — the probability that your data survives hardware failures. S3's 11 nines far exceeds any on-premises RAID configuration."},
]

