# BATCH 2 — Difficulty 2 (fill to 110)
# ══════════════════════════════════════════════════════════════════════════════
questions += [
  {"question_text":"What is the difference between Amazon S3 Standard and S3 One Zone-IA?","options":["S3 Standard stores data in one AZ; One Zone-IA stores in multiple","S3 Standard stores data across multiple AZs; One Zone-IA stores in a single AZ at lower cost","They are identical","One Zone-IA is faster than Standard"],"correct_answer":"S3 Standard stores data across multiple AZs; One Zone-IA stores in a single AZ at lower cost","explanation":"S3 Standard replicates data across at least 3 AZs for high durability. S3 One Zone-IA stores data in a single AZ — 20% cheaper than Standard-IA but data is lost if the AZ is destroyed.","memory_technique":"One Zone-IA = One basket for your eggs. Cheaper, but if that AZ fails, data is gone. Use for reproducible data only.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"One Zone-IA is equivalent to storing data on a single server without RAID — cheaper but higher risk. Suitable for data that can be recreated if lost."},
  {"question_text":"What is Amazon CloudWatch Alarms?","options":["Notifications sent when AWS bills exceed a threshold","Automated actions triggered when a metric crosses a defined threshold","Security alerts for IAM violations","Alerts for EC2 instance failures only"],"correct_answer":"Automated actions triggered when a metric crosses a defined threshold","explanation":"CloudWatch Alarms watch a single metric and perform actions when the metric crosses a threshold. Actions can include sending SNS notifications, triggering Auto Scaling, or stopping/terminating EC2 instances.","memory_technique":"CloudWatch Alarm = Smoke detector for metrics. When CPU hits 90%, the alarm goes off and takes action.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"CloudWatch Alarms are equivalent to monitoring thresholds in Nagios or Zabbix — automated alerts and actions when metrics exceed defined limits."},
  {"question_text":"What is AWS CloudTrail Lake?","options":["A data lake for storing S3 objects","A managed data lake for storing, querying, and analysing CloudTrail events","A lake of CloudWatch metrics","A storage service for CloudFormation templates"],"correct_answer":"A managed data lake for storing, querying, and analysing CloudTrail events","explanation":"AWS CloudTrail Lake is a managed data lake for CloudTrail events. It allows you to aggregate, store, and query CloudTrail events using SQL for security investigations and compliance auditing.","memory_technique":"CloudTrail Lake = Audit log data lake. Store years of API call history and query it with SQL.","topic_area":"Security and Compliance","difficulty_level":2,"it_context_mapping":"CloudTrail Lake is equivalent to a SIEM's long-term log storage and query capability — storing audit logs for years and enabling SQL-based forensic investigation."},
  {"question_text":"What is Amazon Inspector v2?","options":["A manual security assessment service","An automated vulnerability management service that continuously scans EC2 instances and container images","A compliance reporting tool","A network traffic analyser"],"correct_answer":"An automated vulnerability management service that continuously scans EC2 instances and container images","explanation":"Amazon Inspector v2 is an automated vulnerability management service that continuously scans EC2 instances, Lambda functions, and container images for software vulnerabilities and unintended network exposure.","memory_technique":"Inspector v2 = Always-on vulnerability scanner. Continuously checks for CVEs — no manual scheduling needed.","topic_area":"Security and Compliance","difficulty_level":2,"it_context_mapping":"Inspector v2 replaces scheduled vulnerability scans with continuous scanning — equivalent to running Nessus or Qualys continuously rather than weekly."},
  {"question_text":"What is the purpose of an Elastic IP address?","options":["An IP address that automatically scales","A static public IPv4 address that you can allocate to your AWS account and associate with EC2 instances","A private IP address for VPC resources","A dynamic IP address assigned by DHCP"],"correct_answer":"A static public IPv4 address that you can allocate to your AWS account and associate with EC2 instances","explanation":"An Elastic IP is a static public IPv4 address that you can allocate to your account. Unlike regular public IPs that change when you stop/start an instance, Elastic IPs remain constant.","memory_technique":"Elastic IP = Sticky public IP. Stays with your account even when you stop the instance — like a permanent phone number.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"Elastic IPs are equivalent to static IP addresses from an ISP — a fixed public IP that doesn't change, needed for DNS records and firewall whitelisting."},
  {"question_text":"What is Amazon VPC Subnets?","options":["Virtual private connections","Segments of a VPC's IP address range where you can place groups of isolated resources","Security groups for VPCs","Route tables for VPCs"],"correct_answer":"Segments of a VPC's IP address range where you can place groups of isolated resources","explanation":"Subnets are segments of a VPC's IP address range. Public subnets have a route to the internet gateway; private subnets do not. Resources in different subnets can be isolated from each other.","memory_technique":"Subnet = Sub-network. Divide your VPC into smaller networks — public (internet-facing) and private (internal only).","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"VPC subnets are equivalent to VLANs in traditional networking — logical network segments that isolate different tiers of an application (web, app, database)."},
  {"question_text":"What is an Internet Gateway in AWS?","options":["A VPN endpoint","A horizontally scaled, redundant VPC component that allows communication between a VPC and the internet","A NAT device for private subnets","A DNS resolver"],"correct_answer":"A horizontally scaled, redundant VPC component that allows communication between a VPC and the internet","explanation":"An Internet Gateway is a VPC component that allows communication between instances in your VPC and the internet. It is horizontally scaled, redundant, and highly available.","memory_technique":"Internet Gateway = Front door to the internet. Attach it to your VPC and public subnets can reach the internet.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"An Internet Gateway is equivalent to a router with a public IP at the edge of a network — it provides the connection between your private network and the public internet."},
  {"question_text":"What is a NAT Gateway?","options":["A network address translation device that allows private subnet instances to initiate outbound internet connections","A gateway for connecting to on-premises networks","A DNS translation service","A load balancer for private subnets"],"correct_answer":"A network address translation device that allows private subnet instances to initiate outbound internet connections","explanation":"A NAT Gateway allows instances in private subnets to initiate outbound connections to the internet while preventing inbound connections from the internet. It translates private IPs to a public IP.","memory_technique":"NAT Gateway = One-way door to the internet. Private instances can go out; internet cannot come in.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"NAT Gateway is equivalent to a NAT router in traditional networking — it allows servers in a private network to access the internet without exposing them to inbound connections."},
  {"question_text":"What is Amazon Route 53 health checking?","options":["A service that checks the health of Route 53 itself","A feature that monitors the health of endpoints and routes traffic away from unhealthy ones","A billing health check","A security health check"],"correct_answer":"A feature that monitors the health of endpoints and routes traffic away from unhealthy ones","explanation":"Route 53 health checks monitor the health of your endpoints (web servers, email servers, etc.) and can automatically route traffic away from unhealthy endpoints to healthy ones.","memory_technique":"Route 53 health check = Traffic cop with a health monitor. Stops sending cars to a broken road.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"Route 53 health checking is equivalent to DNS-based load balancing with health monitoring — automatically removing failed servers from DNS rotation."},
  {"question_text":"What is AWS CloudFormation drift detection?","options":["A feature that detects when CloudFormation templates have syntax errors","A feature that detects when actual resource configurations differ from the CloudFormation template","A feature that detects unused CloudFormation stacks","A feature that detects CloudFormation cost overruns"],"correct_answer":"A feature that detects when actual resource configurations differ from the CloudFormation template","explanation":"CloudFormation drift detection identifies resources whose actual configuration differs from the expected configuration defined in the CloudFormation template — caused by manual changes outside of CloudFormation.","memory_technique":"Drift detection = Finds when reality drifts from the blueprint. Manual changes = drift. CloudFormation catches the difference.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"Drift detection is equivalent to configuration compliance scanning — detecting when servers have been manually changed from their desired state, similar to Chef/Puppet compliance reports."},
  {"question_text":"What is Amazon S3 lifecycle policies?","options":["Policies that control who can access S3 buckets","Rules that automatically transition objects between storage classes or delete them after a specified time","Policies that control S3 bucket creation","Rules that control S3 replication"],"correct_answer":"Rules that automatically transition objects between storage classes or delete them after a specified time","explanation":"S3 lifecycle policies automate the management of objects. You can transition objects to cheaper storage classes (e.g., Standard → Standard-IA → Glacier) after a specified number of days, or delete them automatically.","memory_technique":"Lifecycle policy = Automated filing system. New files stay on your desk (Standard), old files go to the cabinet (IA), ancient files go to the archive (Glacier).","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"S3 lifecycle policies are equivalent to automated storage tiering policies in enterprise storage systems — automatically moving data to cheaper tiers based on age or access patterns."},
  {"question_text":"What is the difference between AWS CloudFormation and AWS CDK?","options":["They are the same","CloudFormation uses JSON/YAML templates; CDK uses programming languages like Python and TypeScript that compile to CloudFormation","CDK is deprecated","CloudFormation is newer than CDK"],"correct_answer":"CloudFormation uses JSON/YAML templates; CDK uses programming languages like Python and TypeScript that compile to CloudFormation","explanation":"CloudFormation uses declarative JSON/YAML templates. The AWS CDK (Cloud Development Kit) lets you define infrastructure using familiar programming languages that compile to CloudFormation templates under the hood.","memory_technique":"CloudFormation = YAML blueprints. CDK = Write infrastructure in Python/TypeScript. CDK generates CloudFormation.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"CDK is like writing Terraform in Python instead of HCL — a higher-level abstraction that generates the underlying infrastructure definition language."},
  {"question_text":"What is Amazon Elastic Transcoder?","options":["A database migration service","A media transcoding service that converts media files into formats required by consumer playback devices","A text translation service","A data format conversion service"],"correct_answer":"A media transcoding service that converts media files into formats required by consumer playback devices","explanation":"Amazon Elastic Transcoder is a media transcoding service in the cloud. It converts media files from their source format into versions that will play on smartphones, tablets, PCs, and TVs.","memory_technique":"Elastic Transcoder = Video format converter. Upload a video, get it back in any format for any device.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"Elastic Transcoder replaces on-premises transcoding servers and software like FFmpeg clusters. It provides managed video transcoding without managing the underlying compute infrastructure."},
  {"question_text":"What is AWS Snowcone?","options":["The largest Snow Family device","The smallest and most portable Snow Family device for edge computing and data transfer","A cold storage service","A serverless compute service"],"correct_answer":"The smallest and most portable Snow Family device for edge computing and data transfer","explanation":"AWS Snowcone is the smallest member of the Snow Family — a small, rugged, portable edge computing and data transfer device. It holds up to 8TB of usable storage and can run EC2 instances at the edge.","memory_technique":"Snowcone = Small snow device. Fits in a backpack. For small data transfers and edge computing in remote locations.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"Snowcone is equivalent to a ruggedised portable hard drive with compute capability — for collecting and processing data in remote locations without reliable internet connectivity."},
  {"question_text":"What is AWS Snowmobile?","options":["A mobile app for AWS","An exabyte-scale data transfer service using a 45-foot shipping container","A small portable data transfer device","A vehicle-mounted edge computing service"],"correct_answer":"An exabyte-scale data transfer service using a 45-foot shipping container","explanation":"AWS Snowmobile is an exabyte-scale data transfer service. AWS drives a 45-foot shipping container to your data center, you load up to 100PB of data, and AWS ships it to an AWS Region.","memory_technique":"Snowmobile = Truck full of hard drives. For moving entire data centers to AWS — when even Snowball Edge is too small.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"Snowmobile is the ultimate sneakernet — physically transporting petabytes of data when network transfer would take years. Equivalent to shipping an entire data center's worth of backup tapes."},
  {"question_text":"What is Amazon Mechanical Turk?","options":["A robotics service","A crowdsourcing marketplace for human intelligence tasks","An AI service for image recognition","A machine learning training service"],"correct_answer":"A crowdsourcing marketplace for human intelligence tasks","explanation":"Amazon Mechanical Turk (MTurk) is a crowdsourcing marketplace that makes it easier to coordinate the use of human intelligence to perform tasks that computers are currently unable to do well.","memory_technique":"Mechanical Turk = Human-powered tasks. Named after the 18th-century chess-playing 'machine' that was actually operated by a human inside.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"MTurk is equivalent to outsourcing data labelling, content moderation, or survey tasks to a distributed workforce — replacing manual internal processes with a managed crowdsourcing platform."},
  {"question_text":"What is the AWS Billing Dashboard?","options":["A tool for managing IAM users","A central location for viewing and managing your AWS costs and usage","A performance monitoring dashboard","A security compliance dashboard"],"correct_answer":"A central location for viewing and managing your AWS costs and usage","explanation":"The AWS Billing Dashboard provides a summary of your current month's costs, forecasted costs, and access to billing tools like Cost Explorer, Budgets, and the Cost and Usage Report.","memory_technique":"Billing Dashboard = Your AWS credit card statement. See what you've spent, what you're forecasted to spend, and manage your billing settings.","topic_area":"Billing and Pricing","difficulty_level":2,"it_context_mapping":"The Billing Dashboard is equivalent to an expense management portal — a central place to view spending, set budgets, and download invoices."},
  {"question_text":"What is the AWS Free Tier limit for AWS Lambda?","options":["100,000 requests per month","1 million requests and 400,000 GB-seconds of compute time per month, always free","Unlimited for the first 12 months","10,000 requests per month"],"correct_answer":"1 million requests and 400,000 GB-seconds of compute time per month, always free","explanation":"The AWS Lambda Always Free tier includes 1 million free requests per month and 400,000 GB-seconds of compute time per month. This never expires — it's not limited to the first 12 months.","memory_technique":"Lambda free tier = 1 million invocations + 400K GB-seconds. Always free — not just 12 months. Enough for most small applications.","topic_area":"Billing and Pricing","difficulty_level":2,"it_context_mapping":"Lambda's generous free tier means many small applications run at zero cost — equivalent to getting a free server for low-traffic workloads."},
  {"question_text":"What is the AWS Free Tier limit for Amazon DynamoDB?","options":["1GB storage and 1 million requests per month for 12 months","25GB of storage and 25 units of read and write capacity, always free","Unlimited for the first month","10GB storage for 12 months"],"correct_answer":"25GB of storage and 25 units of read and write capacity, always free","explanation":"The DynamoDB Always Free tier includes 25GB of storage and 25 provisioned read and write capacity units per month. This is enough to handle up to 200 million requests per month for many applications.","memory_technique":"DynamoDB free tier = 25GB + 25 RCU + 25 WCU. Always free. Enough for a small production application.","topic_area":"Billing and Pricing","difficulty_level":2,"it_context_mapping":"DynamoDB's free tier is equivalent to a free database hosting plan — enough capacity for development, testing, and small production workloads at zero cost."},
  {"question_text":"What is the difference between AWS Cost Explorer and the AWS Cost and Usage Report?","options":["They are the same","Cost Explorer provides interactive visualisations; the CUR provides raw granular data for custom analysis","Cost Explorer is for billing; CUR is for security","CUR provides visualisations; Cost Explorer provides raw data"],"correct_answer":"Cost Explorer provides interactive visualisations; the CUR provides raw granular data for custom analysis","explanation":"Cost Explorer is a visual tool for exploring costs with pre-built reports and filtering. The CUR is a raw data file delivered to S3 containing every line item of your bill — used for custom analysis with Athena or BI tools.","memory_technique":"Cost Explorer = Dashboard (visual). CUR = Raw data dump (for analysts). Explorer for quick insights; CUR for deep analysis.","topic_area":"Billing and Pricing","difficulty_level":2,"it_context_mapping":"Cost Explorer is like a BI dashboard; the CUR is like a raw database export. One is for business users; the other is for data analysts building custom reports."},
  {"question_text":"What is the AWS Pricing model for Amazon CloudFront?","options":["Fixed monthly fee","Pay per GB of data transferred out and per HTTP/HTTPS request","Pay per edge location used","Free for all AWS customers"],"correct_answer":"Pay per GB of data transferred out and per HTTP/HTTPS request","explanation":"CloudFront pricing is based on data transfer out to the internet (per GB, varying by region) and HTTP/HTTPS requests (per 10,000 requests). Data transfer from AWS origins to CloudFront is free.","memory_technique":"CloudFront = Pay for delivery. Data out + requests. No charge for the trip from your origin to CloudFront.","topic_area":"Billing and Pricing","difficulty_level":2,"it_context_mapping":"CloudFront pricing mirrors traditional CDN pricing — you pay for bandwidth delivered to end users and the number of requests served."},
  {"question_text":"What is the AWS Pricing model for Amazon Route 53?","options":["Fixed monthly fee","Pay per hosted zone per month, plus per million DNS queries","Free for all AWS customers","Pay per domain registration only"],"correct_answer":"Pay per hosted zone per month, plus per million DNS queries","explanation":"Route 53 pricing includes: $0.50 per hosted zone per month (first 25 zones), plus per million DNS queries (varying by query type and routing policy). Domain registration is charged separately per domain per year.","memory_technique":"Route 53 = Pay per zone + per query. Hosted zone = your domain's DNS records. Queries = DNS lookups.","topic_area":"Billing and Pricing","difficulty_level":2,"it_context_mapping":"Route 53 pricing mirrors traditional DNS hosting fees — a monthly fee per domain zone plus usage-based query charges."},
  {"question_text":"What is the AWS Pricing model for Elastic Load Balancing?","options":["Fixed monthly fee","Pay per load balancer hour and per LCU (Load Balancer Capacity Unit) consumed","Free for all AWS customers","Pay per connection only"],"correct_answer":"Pay per load balancer hour and per LCU (Load Balancer Capacity Unit) consumed","explanation":"ELB pricing is based on the number of hours the load balancer runs and the number of Load Balancer Capacity Units (LCUs) consumed. LCUs measure the dimensions on which the load balancer processes traffic.","memory_technique":"ELB = Pay per hour + per LCU. LCU = unit of load balancer work. More traffic = more LCUs = more cost.","topic_area":"Billing and Pricing","difficulty_level":2,"it_context_mapping":"ELB pricing mirrors hardware load balancer licensing — you pay for the appliance (hourly) and the traffic it processes (LCUs)."},
  {"question_text":"What is the AWS Pricing model for Amazon VPC?","options":["Pay per VPC per month","Most VPC features are free; charges apply for NAT Gateway, VPN connections, and data transfer","Fixed monthly fee","Pay per subnet"],"correct_answer":"Most VPC features are free; charges apply for NAT Gateway, VPN connections, and data transfer","explanation":"Creating a VPC, subnets, route tables, internet gateways, and security groups is free. Charges apply for NAT Gateways (per hour + per GB), VPN connections (per hour), and data transfer.","memory_technique":"VPC = Free network. Pay for the extras: NAT Gateway, VPN, data transfer. The network itself is free.","topic_area":"Billing and Pricing","difficulty_level":2,"it_context_mapping":"VPC pricing mirrors network infrastructure costs — the logical network is free, but you pay for managed services (NAT, VPN) and bandwidth."},
  {"question_text":"What is the AWS Pricing model for AWS CloudFormation?","options":["Pay per stack","CloudFormation itself is free; you pay for the AWS resources it creates","Fixed monthly fee","Pay per template"],"correct_answer":"CloudFormation itself is free; you pay for the AWS resources it creates","explanation":"There is no additional charge for AWS CloudFormation. You pay only for the AWS resources that CloudFormation creates — EC2 instances, S3 buckets, RDS databases, etc.","memory_technique":"CloudFormation = Free blueprint service. You pay for the building materials (AWS resources), not the architect (CloudFormation).","topic_area":"Billing and Pricing","difficulty_level":2,"it_context_mapping":"CloudFormation pricing mirrors the model of free infrastructure automation tools — the orchestration is free, you pay for the underlying resources provisioned."},
]

# ══════════════════════════════════════════════════════════════════════════════
# BATCH 2 — Difficulty 3 (fill to 110)
# ══════════════════════════════════════════════════════════════════════════════
questions += [
  {"question_text":"What is the difference between Amazon RDS and Amazon Aurora?","options":["They are the same","RDS supports standard database engines; Aurora is a cloud-native engine with better performance and availability","Aurora is cheaper than RDS","RDS is serverless; Aurora is not"],"correct_answer":"RDS supports standard database engines; Aurora is a cloud-native engine with better performance and availability","explanation":"RDS supports MySQL, PostgreSQL, MariaDB, Oracle, and SQL Server. Aurora is AWS's own cloud-native relational database that is MySQL and PostgreSQL compatible but delivers up to 5x better performance and has a distributed storage architecture.","memory_technique":"RDS = Standard engines managed by AWS. Aurora = AWS's turbocharged engine. Same SQL, better performance.","topic_area":"Technology","difficulty_level":3,"it_context_mapping":"Aurora is like a high-performance database appliance vs. a standard server — same SQL interface but purpose-built for cloud performance."},
  {"question_text":"What is the purpose of Amazon VPC Flow Logs?","options":["To log application errors","To capture IP traffic information for network interfaces in a VPC for security and troubleshooting","To monitor EC2 performance","To log S3 access"],"correct_answer":"To capture IP traffic information for network interfaces in a VPC for security and troubleshooting","explanation":"VPC Flow Logs capture information about IP traffic going to and from network interfaces. They are used for security analysis, troubleshooting connectivity issues, and compliance auditing.","memory_technique":"Flow Logs = Traffic camera for your VPC. Records every packet's source, destination, and whether it was accepted or rejected.","topic_area":"Security and Compliance","difficulty_level":3,"it_context_mapping":"VPC Flow Logs are equivalent to NetFlow data from network switches — they provide visibility into network traffic patterns for security monitoring and troubleshooting."},
  {"question_text":"What is the AWS Well-Architected Framework's Cost Optimisation pillar?","options":["Reducing security costs","Avoiding unnecessary costs by understanding spending, selecting the right resources, and scaling to meet demand","Optimising application performance","Reducing operational overhead"],"correct_answer":"Avoiding unnecessary costs by understanding spending, selecting the right resources, and scaling to meet demand","explanation":"The Cost Optimisation pillar focuses on avoiding unnecessary costs. Key topics include understanding spending, selecting the right resource types and sizes, analysing spend over time, and scaling to meet business needs without overspending.","memory_technique":"Cost Optimisation = Spend wisely. Right size, right price, right time. Don't pay for what you don't use.","topic_area":"Billing and Pricing","difficulty_level":3,"it_context_mapping":"Cost Optimisation maps to traditional IT financial management — capacity planning, licence optimisation, and eliminating waste from the IT budget."},
  {"question_text":"What is Amazon Elastic File System (EFS) and when would you use it over EBS?","options":["EFS is block storage; use it instead of EBS for databases","EFS is a shared file system accessible by multiple EC2 instances simultaneously; use it when multiple instances need to share files","EFS is faster than EBS for all workloads","EFS is cheaper than EBS for all use cases"],"correct_answer":"EFS is a shared file system accessible by multiple EC2 instances simultaneously; use it when multiple instances need to share files","explanation":"EFS provides a shared file system that multiple EC2 instances can mount simultaneously. Use EFS when you need shared access to files across multiple instances (e.g., web server content, shared application data). Use EBS for single-instance block storage.","memory_technique":"EFS = Shared network drive (many instances). EBS = Personal hard drive (one instance). EFS for sharing; EBS for dedicated.","topic_area":"Technology","difficulty_level":3,"it_context_mapping":"EFS is equivalent to NFS shares in traditional IT — a shared file system that multiple servers mount simultaneously. EBS is equivalent to a SAN LUN attached to a single server."},
  {"question_text":"What is the difference between Amazon SQS Standard and FIFO queues?","options":["Standard guarantees order; FIFO does not","FIFO guarantees exactly-once processing and strict ordering; Standard offers higher throughput but may deliver out of order","They are identical","Standard is for large messages; FIFO is for small messages"],"correct_answer":"FIFO guarantees exactly-once processing and strict ordering; Standard offers higher throughput but may deliver out of order","explanation":"SQS Standard queues offer maximum throughput and at-least-once delivery but may deliver messages out of order or more than once. FIFO queues guarantee exactly-once processing and strict first-in-first-out ordering.","memory_technique":"Standard = Fast but messy. FIFO = Orderly queue. Choose FIFO when order matters (financial transactions); Standard when throughput matters.","topic_area":"Technology","difficulty_level":3,"it_context_mapping":"Standard queues are like a busy post office where letters might arrive out of order. FIFO queues are like a numbered ticket system — strict order guaranteed."},
  {"question_text":"What is AWS Elastic Beanstalk's deployment policy 'Rolling with additional batch'?","options":["Deploys to all instances simultaneously","Deploys to a batch of instances while launching additional instances to maintain capacity","Deploys to one instance at a time","Deploys to a new environment then switches traffic"],"correct_answer":"Deploys to a batch of instances while launching additional instances to maintain capacity","explanation":"Rolling with additional batch launches a new batch of instances before taking any existing instances out of service. This maintains full capacity during deployment, unlike standard rolling which temporarily reduces capacity.","memory_technique":"Rolling with additional batch = Deploy without losing capacity. Launch new instances first, then update old ones. Full capacity throughout.","topic_area":"Technology","difficulty_level":3,"it_context_mapping":"This is equivalent to a rolling deployment with capacity buffer — maintaining full production capacity during the update by temporarily running extra instances."},
  {"question_text":"What is the purpose of AWS Systems Manager Parameter Store?","options":["To store EC2 instance parameters","To provide secure, hierarchical storage for configuration data and secrets","To store CloudFormation parameters","To store IAM policy parameters"],"correct_answer":"To provide secure, hierarchical storage for configuration data and secrets","explanation":"AWS Systems Manager Parameter Store provides secure, hierarchical storage for configuration data management and secrets management. It can store plain text or encrypted values and integrates with IAM for access control.","memory_technique":"Parameter Store = Config and secrets vault. Store database passwords, API keys, and config values securely — retrieve them in your code without hardcoding.","topic_area":"Technology","difficulty_level":3,"it_context_mapping":"Parameter Store is equivalent to a configuration management database (CMDB) for application settings — centralised, versioned, and access-controlled storage for configuration values."},
  {"question_text":"What is Amazon Kinesis Data Firehose?","options":["A real-time data streaming service","A fully managed service for loading streaming data into data stores like S3, Redshift, and Elasticsearch","A message queue service","A batch data processing service"],"correct_answer":"A fully managed service for loading streaming data into data stores like S3, Redshift, and Elasticsearch","explanation":"Kinesis Data Firehose is the easiest way to reliably load streaming data into data lakes, data stores, and analytics services. It automatically scales and handles batching, compression, and encryption.","memory_technique":"Firehose = Fire hose of data. Streams data directly into S3, Redshift, or Elasticsearch — no custom consumer code needed.","topic_area":"Technology","difficulty_level":3,"it_context_mapping":"Kinesis Firehose is equivalent to a managed ETL pipeline that continuously loads streaming data into a data warehouse — replacing custom Kafka consumer applications."},
  {"question_text":"What is the difference between AWS Lambda and AWS Fargate?","options":["They are the same","Lambda runs individual functions triggered by events; Fargate runs containers without managing servers","Lambda is for containers; Fargate is for functions","Fargate is serverless; Lambda is not"],"correct_answer":"Lambda runs individual functions triggered by events; Fargate runs containers without managing servers","explanation":"Lambda is for running individual functions in response to events — short-lived, event-driven code. Fargate runs containerised applications without managing EC2 instances — longer-running services in containers.","memory_technique":"Lambda = Function (event-driven, milliseconds). Fargate = Container (service, long-running). Lambda for events; Fargate for services.","topic_area":"Technology","difficulty_level":3,"it_context_mapping":"Lambda is like a serverless function (FaaS); Fargate is like a serverless container platform (CaaS). Lambda for event handlers; Fargate for microservices."},
  {"question_text":"What is Amazon CloudFront's origin?","options":["The edge location closest to the user","The source server or service that CloudFront retrieves content from when it's not cached","The CloudFront distribution itself","The DNS server for CloudFront"],"correct_answer":"The source server or service that CloudFront retrieves content from when it's not cached","explanation":"A CloudFront origin is the source of the content that CloudFront distributes. Origins can be S3 buckets, EC2 instances, Elastic Load Balancers, or any HTTP server. CloudFront fetches content from the origin when it's not in the edge cache.","memory_technique":"Origin = The source. CloudFront caches content from the origin at edge locations. Cache miss = go back to origin.","topic_area":"Technology","difficulty_level":3,"it_context_mapping":"CloudFront origin is equivalent to the origin server in traditional CDN architecture — the authoritative source that the CDN pulls content from when the cache is empty."},
  {"question_text":"What is the purpose of AWS Config's managed rules?","options":["To configure EC2 instances","Pre-built compliance rules that evaluate whether AWS resources comply with common best practices","To manage IAM policies","To configure network routing"],"correct_answer":"Pre-built compliance rules that evaluate whether AWS resources comply with common best practices","explanation":"AWS Config managed rules are pre-built rules that evaluate whether your AWS resources comply with common best practices. Examples include checking if S3 buckets have encryption enabled, if EC2 instances are in a VPC, or if MFA is enabled on the root account.","memory_technique":"Managed rules = Pre-written compliance checklist. AWS provides the rules; you just enable them.","topic_area":"Security and Compliance","difficulty_level":3,"it_context_mapping":"Config managed rules are equivalent to pre-built compliance policy templates in GRC tools — standard checks for common security and compliance requirements."},
  {"question_text":"What is the difference between AWS Secrets Manager and AWS Systems Manager Parameter Store?","options":["They are identical","Secrets Manager provides automatic secret rotation and is designed for secrets; Parameter Store is for configuration data and has a free tier","Parameter Store rotates secrets; Secrets Manager stores configuration","Secrets Manager is free; Parameter Store costs money"],"correct_answer":"Secrets Manager provides automatic secret rotation and is designed for secrets; Parameter Store is for configuration data and has a free tier","explanation":"Secrets Manager is purpose-built for secrets with automatic rotation, cross-account access, and native integration with RDS, Redshift, and DocumentDB. Parameter Store is for configuration data and secrets with a free tier for standard parameters.","memory_technique":"Secrets Manager = Rotating vault (auto-rotation, costs money). Parameter Store = Config + secrets (free tier, manual rotation). Use Secrets Manager for database passwords that need auto-rotation.","topic_area":"Security and Compliance","difficulty_level":3,"it_context_mapping":"Secrets Manager is like a PAM (Privileged Access Management) system with automatic password rotation; Parameter Store is like a configuration management database that also stores secrets."},
  {"question_text":"What is Amazon Cognito's User Pool?","options":["A pool of EC2 instances","A user directory that provides sign-up, sign-in, and user management for web and mobile apps","A pool of IAM users","A database of application users"],"correct_answer":"A user directory that provides sign-up, sign-in, and user management for web and mobile apps","explanation":"A Cognito User Pool is a user directory that provides sign-up and sign-in options for your app users. It handles user registration, authentication, account recovery, and supports MFA and social identity providers.","memory_technique":"User Pool = User directory in the cloud. Like Active Directory but for your app's users — handles registration, login, and MFA.","topic_area":"Security and Compliance","difficulty_level":3,"it_context_mapping":"Cognito User Pools are equivalent to a managed LDAP/AD directory for application users — handling authentication without building custom user management systems."},
  {"question_text":"What is the purpose of Amazon CloudWatch Logs Insights?","options":["To create CloudWatch dashboards","An interactive query service for analysing log data stored in CloudWatch Logs","To set up CloudWatch alarms","To export logs to S3"],"correct_answer":"An interactive query service for analysing log data stored in CloudWatch Logs","explanation":"CloudWatch Logs Insights enables you to interactively search and analyse your log data in CloudWatch Logs using a purpose-built query language. It can query millions of log events in seconds.","memory_technique":"Logs Insights = SQL for your logs. Query your CloudWatch logs like a database — find errors, patterns, and anomalies fast.","topic_area":"Technology","difficulty_level":3,"it_context_mapping":"CloudWatch Logs Insights is equivalent to Splunk's search language or Elasticsearch's query DSL — a powerful query interface for log analysis."},
  {"question_text":"What is the AWS Pricing model for Amazon SQS?","options":["Fixed monthly fee","Pay per million requests, with the first 1 million requests per month free","Pay per message size","Pay per queue"],"correct_answer":"Pay per million requests, with the first 1 million requests per month free","explanation":"SQS pricing is based on the number of requests (API calls). The first 1 million SQS requests per month are free. After that, pricing is per million requests, varying by queue type (Standard vs FIFO).","memory_technique":"SQS = Pay per million requests. First million free. FIFO costs slightly more than Standard.","topic_area":"Billing and Pricing","difficulty_level":3,"it_context_mapping":"SQS pricing mirrors message broker pricing — you pay for the number of messages processed, not for the infrastructure running the broker."},
  {"question_text":"What is the AWS Pricing model for Amazon SNS?","options":["Fixed monthly fee","Pay per million publishes and per million deliveries, with a free tier","Pay per topic","Pay per subscriber"],"correct_answer":"Pay per million publishes and per million deliveries, with a free tier","explanation":"SNS pricing is based on the number of publishes (messages sent to topics) and deliveries (notifications sent to subscribers). The first 1 million publishes and deliveries per month are free.","memory_technique":"SNS = Pay per publish + per delivery. Publish to topic = one charge. Deliver to each subscriber = another charge.","topic_area":"Billing and Pricing","difficulty_level":3,"it_context_mapping":"SNS pricing mirrors notification service pricing — you pay for the messages sent and the notifications delivered to each endpoint."},
  {"question_text":"What is the AWS Pricing model for AWS Glue?","options":["Fixed monthly fee","Pay per DPU-hour for ETL jobs and crawlers, plus storage for the Data Catalog","Pay per data processed","Free for all customers"],"correct_answer":"Pay per DPU-hour for ETL jobs and crawlers, plus storage for the Data Catalog","explanation":"AWS Glue pricing is based on DPU-hours (Data Processing Units) consumed by ETL jobs and crawlers. The Glue Data Catalog charges per month for objects stored beyond the free tier.","memory_technique":"Glue = Pay per DPU-hour. DPU = unit of Glue compute. More complex ETL = more DPUs = more cost.","topic_area":"Billing and Pricing","difficulty_level":3,"it_context_mapping":"Glue pricing mirrors Spark cluster pricing — you pay for the compute resources consumed during ETL job execution, not for idle infrastructure."},
  {"question_text":"What is the AWS Pricing model for Amazon Athena?","options":["Fixed monthly fee","Pay per TB of data scanned by queries","Pay per query","Pay per table"],"correct_answer":"Pay per TB of data scanned by queries","explanation":"Athena pricing is based on the amount of data scanned per query ($5 per TB scanned). You can reduce costs by using columnar formats (Parquet, ORC) and partitioning data to scan less.","memory_technique":"Athena = Pay per TB scanned. Scan less = pay less. Use Parquet + partitions to minimise scanned data.","topic_area":"Billing and Pricing","difficulty_level":3,"it_context_mapping":"Athena's per-scan pricing incentivises data optimisation — using columnar formats and partitioning reduces costs, similar to query optimisation in traditional databases."},
  {"question_text":"What is the AWS Pricing model for Amazon Kinesis Data Firehose?","options":["Fixed monthly fee","Pay per GB of data ingested","Pay per shard-hour","Free for all customers"],"correct_answer":"Pay per GB of data ingested","explanation":"Kinesis Data Firehose pricing is based on the volume of data ingested (per GB). There are no upfront costs or minimum fees. Optional features like format conversion and data transformation have additional charges.","memory_technique":"Firehose = Pay per GB flowing through. More data = more cost. Simple per-GB pricing.","topic_area":"Billing and Pricing","difficulty_level":3,"it_context_mapping":"Firehose pricing mirrors managed ETL pipeline pricing — you pay for the data volume processed, not for the infrastructure running the pipeline."},
  {"question_text":"What is the AWS Pricing model for Amazon Redshift?","options":["Pay per query","Pay per node-hour for provisioned clusters, or per RPU-second for serverless","Fixed monthly fee","Pay per GB of data stored only"],"correct_answer":"Pay per node-hour for provisioned clusters, or per RPU-second for serverless","explanation":"Redshift Provisioned charges per node-hour based on node type. Redshift Serverless charges per RPU-second for compute plus storage. Reserved Nodes provide significant discounts for 1 or 3-year commitments.","memory_technique":"Redshift Provisioned = Pay per node per hour (like EC2). Redshift Serverless = Pay per RPU-second (like Lambda). Choose based on workload predictability.","topic_area":"Billing and Pricing","difficulty_level":3,"it_context_mapping":"Redshift pricing mirrors data warehouse appliance pricing — provisioned capacity for predictable workloads, serverless for variable or intermittent analytics."},
]

