# BATCH 3 — Difficulty 4 (more coverage)
# ══════════════════════════════════════════════════════════════════════════════
questions += [
  {"question_text":"What is the difference between AWS Global Accelerator and Amazon CloudFront?","options":["They are the same","CloudFront caches content at edge locations; Global Accelerator routes traffic through the AWS network without caching for improved performance of dynamic content","CloudFront is for dynamic content; Global Accelerator is for static content","Global Accelerator is a CDN"],"correct_answer":"CloudFront caches content at edge locations; Global Accelerator routes traffic through the AWS network without caching for improved performance of dynamic content","explanation":"CloudFront is a CDN that caches static content at edge locations. Global Accelerator routes all traffic (including dynamic) through the AWS global network for lower latency and provides static anycast IP addresses.","memory_technique":"CloudFront = Cache at edge (static). Global Accelerator = Fast lane on AWS network (dynamic, static IPs). One caches; the other routes.","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"CloudFront is like a CDN for static assets; Global Accelerator is like a private WAN for dynamic traffic — both improve performance through different mechanisms."},
  {"question_text":"A company needs to run Windows workloads that require persistent file storage with SMB protocol support. Which AWS service should they use?","options":["Amazon EFS","Amazon S3","Amazon FSx for Windows File Server","Amazon EBS"],"correct_answer":"Amazon FSx for Windows File Server","explanation":"Amazon FSx for Windows File Server provides fully managed Windows file systems with native SMB protocol support, Active Directory integration, and Windows NTFS. It's purpose-built for Windows workloads.","memory_technique":"FSx for Windows = Managed Windows file server. SMB + AD + NTFS — everything Windows apps expect.","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"FSx for Windows replaces on-premises Windows file servers and DFS shares. It provides the same SMB protocol and AD integration without managing Windows Server infrastructure."},
  {"question_text":"What is the difference between Amazon Kinesis Data Streams and Amazon Kinesis Data Firehose?","options":["They are the same","Data Streams requires custom consumers and provides more control; Firehose automatically delivers data to destinations without custom code","Data Streams is for batch; Firehose is for real-time","Firehose requires custom consumers; Data Streams does not"],"correct_answer":"Data Streams requires custom consumers and provides more control; Firehose automatically delivers data to destinations without custom code","explanation":"Kinesis Data Streams gives you full control — you write custom consumers to process data. Firehose is fully managed — it automatically batches, compresses, and delivers data to S3, Redshift, or Elasticsearch without custom code.","memory_technique":"Data Streams = DIY (custom consumers, more control). Firehose = Automatic delivery (no code, just configure destination).","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"Data Streams is like running your own Kafka consumers; Firehose is like a managed Kafka Connect sink — automatic delivery without writing consumer code."},
  {"question_text":"What is Amazon EventBridge Scheduler?","options":["A service for scheduling EC2 instances","A serverless scheduler for creating, running, and managing scheduled tasks at scale","A calendar service for AWS teams","A service for scheduling database backups"],"correct_answer":"A serverless scheduler for creating, running, and managing scheduled tasks at scale","explanation":"EventBridge Scheduler is a serverless scheduler that allows you to create, run, and manage scheduled tasks at scale. It can invoke over 270 AWS services and 6,000+ API actions on a schedule.","memory_technique":"EventBridge Scheduler = Cron job in the cloud. Schedule any AWS action — no servers to manage.","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"EventBridge Scheduler replaces cron jobs on EC2 instances and CloudWatch Events scheduled rules. It provides a dedicated, scalable scheduling service."},
  {"question_text":"What is the purpose of AWS Backup?","options":["To back up IAM policies","A centralised service for automating and managing backups across AWS services","To back up CloudFormation templates","To back up billing data"],"correct_answer":"A centralised service for automating and managing backups across AWS services","explanation":"AWS Backup is a fully managed backup service that centralises and automates data protection across AWS services including EC2, EBS, RDS, DynamoDB, EFS, and S3.","memory_technique":"AWS Backup = One backup service to rule them all. Centralised backup policies across all your AWS resources.","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"AWS Backup replaces multiple backup tools and scripts. It's equivalent to enterprise backup software like Veeam or Commvault — one tool managing backups across all infrastructure."},
  {"question_text":"What is the difference between AWS WAF managed rules and custom rules?","options":["They are the same","Managed rules are pre-built by AWS or partners; custom rules are written by you for specific application needs","Managed rules are free; custom rules cost money","Custom rules are pre-built; managed rules are custom"],"correct_answer":"Managed rules are pre-built by AWS or partners; custom rules are written by you for specific application needs","explanation":"WAF managed rules are pre-built rule groups maintained by AWS or AWS Marketplace sellers (e.g., OWASP Top 10, bot protection). Custom rules are rules you write yourself to address your specific application's security needs.","memory_technique":"Managed rules = Off-the-shelf protection (OWASP, bots). Custom rules = Tailored protection (your app's specific needs).","topic_area":"Security and Compliance","difficulty_level":4,"it_context_mapping":"Managed rules are like signature-based IDS rules from vendors; custom rules are like custom firewall rules written by your security team for application-specific threats."},
  {"question_text":"What is AWS Control Tower's Account Factory?","options":["A service for manufacturing physical servers","A feature that automates the provisioning of new AWS accounts with pre-configured settings and guardrails","A tool for creating IAM users","A service for managing EC2 instances"],"correct_answer":"A feature that automates the provisioning of new AWS accounts with pre-configured settings and guardrails","explanation":"Account Factory in AWS Control Tower automates the provisioning of new AWS accounts. Each new account is automatically configured with the organisation's baseline settings, networking, and guardrails.","memory_technique":"Account Factory = Assembly line for AWS accounts. Stamp out new accounts with consistent configuration — like a cookie cutter.","topic_area":"Cloud Concepts","difficulty_level":4,"it_context_mapping":"Account Factory is equivalent to an automated IT provisioning system that creates new environments with standard configurations — like a self-service portal for new project environments."},
  {"question_text":"What is the purpose of AWS Service Catalog?","options":["A catalogue of all AWS services","A service that allows organisations to create and manage catalogues of approved IT services for deployment on AWS","A marketplace for third-party software","A documentation service"],"correct_answer":"A service that allows organisations to create and manage catalogues of approved IT services for deployment on AWS","explanation":"AWS Service Catalog allows organisations to create and manage catalogues of approved IT services. Users can deploy only approved products, ensuring compliance with organisational standards.","memory_technique":"Service Catalog = Approved menu of IT services. Users can only order from the menu — no unapproved deployments.","topic_area":"Cloud Concepts","difficulty_level":4,"it_context_mapping":"Service Catalog is equivalent to a self-service IT portal where users can request pre-approved infrastructure — like ServiceNow's service catalogue for IT requests."},
  {"question_text":"What is the difference between AWS Transit Gateway and VPC Peering?","options":["They are the same","Transit Gateway is a hub-and-spoke model connecting many VPCs; VPC Peering is point-to-point between two VPCs","VPC Peering supports transitive routing; Transit Gateway does not","Transit Gateway is free; VPC Peering costs money"],"correct_answer":"Transit Gateway is a hub-and-spoke model connecting many VPCs; VPC Peering is point-to-point between two VPCs","explanation":"VPC Peering creates a direct connection between two VPCs (non-transitive). Transit Gateway acts as a central hub connecting multiple VPCs and on-premises networks, supporting transitive routing and simplifying complex network topologies.","memory_technique":"VPC Peering = Direct phone call (one-to-one). Transit Gateway = Conference call hub (many-to-many). TGW scales better for complex networks.","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"VPC Peering is like a point-to-point WAN link; Transit Gateway is like a core router in a hub-and-spoke WAN — centralising routing for many branch connections."},
  {"question_text":"What is Amazon MemoryDB for Redis?","options":["An in-memory cache service","A Redis-compatible, durable, in-memory database service for ultra-fast performance with data durability","A managed Redis cluster for caching only","A Redis monitoring service"],"correct_answer":"A Redis-compatible, durable, in-memory database service for ultra-fast performance with data durability","explanation":"Amazon MemoryDB for Redis is a durable, in-memory database that delivers microsecond read and single-digit millisecond write latency with Multi-AZ durability. Unlike ElastiCache (cache), MemoryDB is a primary database.","memory_technique":"MemoryDB = Redis as a database (durable). ElastiCache = Redis as a cache (may lose data). MemoryDB persists; ElastiCache caches.","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"MemoryDB is equivalent to using Redis as a primary database with persistence — providing the speed of in-memory access with the durability guarantees of a traditional database."},
  {"question_text":"What is the purpose of AWS CloudTrail Insights?","options":["To provide insights into CloudTrail pricing","To automatically detect unusual API activity patterns in your AWS account","To provide insights into IAM policy usage","To detect unusual billing patterns"],"correct_answer":"To automatically detect unusual API activity patterns in your AWS account","explanation":"CloudTrail Insights automatically analyses CloudTrail management events to detect unusual API call patterns — such as spikes in resource provisioning, bursts of IAM actions, or gaps in periodic maintenance activity.","memory_technique":"CloudTrail Insights = Anomaly detector for API calls. Spots unusual patterns — like a sudden spike in EC2 launches that might indicate compromised credentials.","topic_area":"Security and Compliance","difficulty_level":4,"it_context_mapping":"CloudTrail Insights is equivalent to UEBA (User and Entity Behavior Analytics) in SIEM systems — detecting anomalous behaviour patterns that might indicate a security incident."},
  {"question_text":"What is the purpose of Amazon GuardDuty S3 Protection?","options":["To encrypt S3 data","To monitor S3 data access patterns and detect suspicious activity like data exfiltration","To back up S3 data","To compress S3 data"],"correct_answer":"To monitor S3 data access patterns and detect suspicious activity like data exfiltration","explanation":"GuardDuty S3 Protection monitors S3 data access events (CloudTrail S3 data events) to detect suspicious activity such as unusual data access patterns, data exfiltration attempts, or access from known malicious IP addresses.","memory_technique":"GuardDuty S3 Protection = Security camera for your S3 buckets. Watches who accesses what and flags suspicious patterns.","topic_area":"Security and Compliance","difficulty_level":4,"it_context_mapping":"GuardDuty S3 Protection is equivalent to DLP monitoring for file servers — detecting unusual data access patterns that might indicate insider threats or data exfiltration."},
  {"question_text":"What is the difference between AWS Backup and native service backups (like RDS automated backups)?","options":["They are the same","AWS Backup provides centralised management across services with cross-account and cross-region capabilities; native backups are service-specific","Native backups are more reliable","AWS Backup is free; native backups cost money"],"correct_answer":"AWS Backup provides centralised management across services with cross-account and cross-region capabilities; native backups are service-specific","explanation":"Native service backups (RDS automated backups, EBS snapshots) are managed per-service. AWS Backup provides a single policy-based interface across all services, with cross-account backup, cross-region copy, and centralised compliance reporting.","memory_technique":"AWS Backup = One ring to rule them all (centralised). Native backups = Each service manages its own. AWS Backup adds cross-account, cross-region, and unified policies.","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"AWS Backup is like enterprise backup software (Veeam, Commvault) that manages backups across all infrastructure from one console, vs. each application managing its own backups independently."},
  {"question_text":"What is the purpose of AWS RAM (Resource Access Manager)?","options":["To manage EC2 instance RAM","To share AWS resources across accounts without creating duplicate resources","To manage IAM roles","To monitor memory usage"],"correct_answer":"To share AWS resources across accounts without creating duplicate resources","explanation":"AWS RAM lets you share resources (VPC subnets, Transit Gateways, Route 53 Resolver rules, License Manager configurations) with other AWS accounts or within your Organisation without duplicating them.","memory_technique":"RAM = Resource Access Manager (not memory!). Share resources between accounts — like sharing a printer on a network instead of buying one per desk.","topic_area":"Security and Compliance","difficulty_level":4,"it_context_mapping":"RAM is equivalent to shared infrastructure in traditional IT — centralised resources (shared network segments, shared services) that multiple teams use without each maintaining their own copy."},
  {"question_text":"What is the purpose of Amazon CloudWatch Contributor Insights?","options":["To identify top contributors to CloudWatch costs","To identify the top contributors to system performance issues by analysing log data","To identify top IAM contributors","To identify top S3 contributors"],"correct_answer":"To identify the top contributors to system performance issues by analysing log data","explanation":"CloudWatch Contributor Insights analyses log data to create time-series visualisations showing the top-N contributors to a metric. For example, identifying the top IP addresses generating errors or the top URLs consuming bandwidth.","memory_technique":"Contributor Insights = Top-N finder. Who's causing the most errors? Which IPs are generating the most traffic? Find the top contributors.","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"Contributor Insights is equivalent to 'top talkers' analysis in network monitoring — identifying the sources responsible for the most traffic, errors, or resource consumption."},
  {"question_text":"What is the AWS Pricing model for AWS Step Functions?","options":["Fixed monthly fee","Pay per state transition","Free for all customers","Pay per workflow definition"],"correct_answer":"Pay per state transition","explanation":"Step Functions pricing is based on the number of state transitions in your workflows. Standard Workflows charge per state transition. Express Workflows charge per execution, duration, and memory.","memory_technique":"Step Functions = Pay per step. Each state transition in your workflow costs money. More steps = more cost.","topic_area":"Billing and Pricing","difficulty_level":4,"it_context_mapping":"Step Functions pricing mirrors workflow engine pricing — you pay for the orchestration work performed, not for idle infrastructure."},
  {"question_text":"What is the AWS Pricing model for AWS Secrets Manager?","options":["Free for all customers","Pay per secret per month plus per 10,000 API calls","Pay per rotation only","Fixed monthly fee"],"correct_answer":"Pay per secret per month plus per 10,000 API calls","explanation":"Secrets Manager charges per secret stored per month ($0.40/secret/month) plus per 10,000 API calls ($0.05). Automatic rotation is included in the per-secret price.","memory_technique":"Secrets Manager = Pay per secret + per API call. Each secret costs ~$0.40/month. Rotation is included.","topic_area":"Billing and Pricing","difficulty_level":4,"it_context_mapping":"Secrets Manager pricing mirrors PAM (Privileged Access Management) tool licensing — per-secret pricing with API call charges for retrieval."},
  {"question_text":"What is the AWS Pricing model for Amazon API Gateway?","options":["Fixed monthly fee","Pay per million API calls received, plus data transfer and optional caching","Pay per API definition","Free for all customers"],"correct_answer":"Pay per million API calls received, plus data transfer and optional caching","explanation":"API Gateway pricing is based on the number of API calls received (per million), data transfer out, and optional caching (per hour for the cache instance). WebSocket APIs charge per million messages and connection minutes.","memory_technique":"API Gateway = Pay per million calls + data transfer. More API traffic = more cost. Caching is optional extra.","topic_area":"Billing and Pricing","difficulty_level":4,"it_context_mapping":"API Gateway pricing mirrors API management platform pricing — per-call charges for the gateway service plus bandwidth costs."},
]

