questions += [
  {"question_text":"What is the purpose of AWS CloudTrail Organisation Trail?","options":["A trail for a single account","A trail that logs events for all accounts in an AWS Organisation to a central S3 bucket","A trail for CloudWatch events","A trail for billing events only"],"correct_answer":"A trail that logs events for all accounts in an AWS Organisation to a central S3 bucket","explanation":"An Organisation Trail in CloudTrail logs events for all accounts in your AWS Organisation to a single S3 bucket in the management account. This provides centralised audit logging across all accounts.","memory_technique":"Organisation Trail = One audit log for all accounts. Central S3 bucket collects API calls from every account in the org.","topic_area":"Security and Compliance","difficulty_level":4,"it_context_mapping":"Organisation Trails are equivalent to centralised SIEM log collection — all audit logs from all systems flow to one central repository for analysis."},
  {"question_text":"What is the purpose of AWS Config Aggregator?","options":["To aggregate EC2 instances","To collect AWS Config data from multiple accounts and regions into a single dashboard","To aggregate billing data","To aggregate CloudWatch metrics"],"correct_answer":"To collect AWS Config data from multiple accounts and regions into a single dashboard","explanation":"AWS Config Aggregator collects configuration and compliance data from multiple accounts and regions into a single aggregator account. This provides a centralised view of compliance across your entire organisation.","memory_technique":"Config Aggregator = Compliance dashboard for all accounts. One view showing compliance status across every account and region.","topic_area":"Security and Compliance","difficulty_level":4,"it_context_mapping":"Config Aggregator is equivalent to a centralised compliance dashboard in GRC tools — aggregating compliance status from all systems into one view for governance teams."},
  {"question_text":"What is the purpose of Amazon S3 Access Points?","options":["Physical access points for S3","Named network endpoints with dedicated access policies that simplify managing data access at scale for shared datasets","S3 API endpoints","S3 transfer acceleration endpoints"],"correct_answer":"Named network endpoints with dedicated access policies that simplify managing data access at scale for shared datasets","explanation":"S3 Access Points are named network endpoints attached to buckets. Each access point has its own permissions policy, making it easier to manage access for shared datasets with many different access patterns.","memory_technique":"Access Points = Dedicated doors to your S3 bucket. Each door has its own key (policy). Simpler than one giant bucket policy.","topic_area":"Security and Compliance","difficulty_level":4,"it_context_mapping":"S3 Access Points are equivalent to creating multiple network shares on a file server — each share has its own permissions, simplifying access management for different teams."},
  {"question_text":"What is the purpose of AWS Trusted Advisor Priority?","options":["A paid version of Trusted Advisor","A feature available with Enterprise Support that provides prioritised recommendations with context from your TAM","A priority queue for support tickets","A priority billing feature"],"correct_answer":"A feature available with Enterprise Support that provides prioritised recommendations with context from your TAM","explanation":"Trusted Advisor Priority (Enterprise Support only) provides prioritised, contextualised recommendations from your Technical Account Manager. It aggregates recommendations from Trusted Advisor, AWS Health, and Well-Architected reviews.","memory_technique":"Trusted Advisor Priority = Curated advice from your TAM. Not just automated checks — human-prioritised recommendations.","topic_area":"Cloud Concepts","difficulty_level":4,"it_context_mapping":"Trusted Advisor Priority is equivalent to having a dedicated consultant who reviews automated findings and prioritises them based on your specific business context."},
  {"question_text":"What is the purpose of AWS Resilience Hub?","options":["A physical data center hub","A service that helps you define, validate, and track the resilience of your applications against defined RTO and RPO targets","A network resilience service","A storage resilience service"],"correct_answer":"A service that helps you define, validate, and track the resilience of your applications against defined RTO and RPO targets","explanation":"AWS Resilience Hub helps you define resilience targets (RTO/RPO) for your applications, assess whether your architecture meets those targets, and provides recommendations to improve resilience.","memory_technique":"Resilience Hub = DR report card. Define your RTO/RPO targets, and Resilience Hub tells you if your architecture meets them.","topic_area":"Cloud Concepts","difficulty_level":4,"it_context_mapping":"Resilience Hub is equivalent to a DR readiness assessment tool — validating that your architecture can meet defined recovery objectives before a disaster occurs."},
  {"question_text":"What is the purpose of Amazon CloudWatch Synthetics?","options":["To synthesise CloudWatch data","To create canary scripts that monitor endpoints and APIs by simulating user behaviour","To generate synthetic metrics","To create synthetic logs"],"correct_answer":"To create canary scripts that monitor endpoints and APIs by simulating user behaviour","explanation":"CloudWatch Synthetics allows you to create canaries — configurable scripts that run on a schedule to monitor endpoints and APIs. They simulate user behaviour and alert you when endpoints don't respond as expected.","memory_technique":"Synthetics = Synthetic users. Fake users that continuously test your endpoints — like a robot clicking through your app 24/7.","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"CloudWatch Synthetics is equivalent to synthetic monitoring tools like Pingdom or Catchpoint — simulating user interactions to detect availability and performance issues before real users are affected."},
  {"question_text":"What is the purpose of AWS Elastic Disaster Recovery (DRS)?","options":["A backup service","A service that minimises downtime and data loss by enabling fast, reliable recovery of on-premises and cloud-based applications using affordable storage and minimal compute","A data replication service","A database recovery service"],"correct_answer":"A service that minimises downtime and data loss by enabling fast, reliable recovery of on-premises and cloud-based applications using affordable storage and minimal compute","explanation":"AWS Elastic Disaster Recovery continuously replicates your source servers to AWS using lightweight agents. During a disaster, you can launch recovery instances in minutes, achieving low RPO (seconds) and low RTO (minutes).","memory_technique":"Elastic DRS = Continuous replication + instant recovery. Replicate continuously, recover in minutes. Like a hot standby that costs almost nothing until you need it.","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"Elastic DRS replaces traditional DR solutions like Zerto or VMware SRM. It provides continuous replication with on-demand recovery instances — paying for full compute only during a disaster."},
  {"question_text":"What is the purpose of AWS Migration Evaluator?","options":["To evaluate AWS service quality","A service that helps build a business case for cloud migration by analysing on-premises resource utilisation and projecting AWS costs","To evaluate IAM policies","To evaluate network performance"],"correct_answer":"A service that helps build a business case for cloud migration by analysing on-premises resource utilisation and projecting AWS costs","explanation":"AWS Migration Evaluator (formerly TSO Logic) analyses your on-premises environment to build a data-driven business case for migration. It collects utilisation data and projects optimised AWS costs.","memory_technique":"Migration Evaluator = Business case builder. Analyses your on-premises estate and shows what it would cost on AWS — with right-sizing recommendations.","topic_area":"Cloud Concepts","difficulty_level":4,"it_context_mapping":"Migration Evaluator is equivalent to a TCO analysis tool — collecting actual utilisation data from your data center and projecting optimised cloud costs."},
  {"question_text":"What is the purpose of AWS Database Migration Service (DMS)?","options":["To migrate IAM databases","A service that helps migrate databases to AWS quickly and securely with minimal downtime","To migrate S3 data","To migrate EC2 instances"],"correct_answer":"A service that helps migrate databases to AWS quickly and securely with minimal downtime","explanation":"AWS DMS helps you migrate databases to AWS with minimal downtime. The source database remains fully operational during migration. It supports homogeneous (Oracle to Oracle) and heterogeneous (Oracle to Aurora) migrations.","memory_technique":"DMS = Database Migration Service. Moves your database to AWS while it's still running — like changing tyres on a moving car.","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"DMS replaces manual database migration processes (export/import, log shipping). It provides continuous replication during migration, minimising the cutover window."},
  {"question_text":"What is the purpose of AWS Schema Conversion Tool (SCT)?","options":["To convert CloudFormation schemas","To convert database schemas and code from one database engine to another for heterogeneous migrations","To convert API schemas","To convert IAM policy schemas"],"correct_answer":"To convert database schemas and code from one database engine to another for heterogeneous migrations","explanation":"AWS SCT converts database schemas, stored procedures, and application code from one database engine to another (e.g., Oracle to PostgreSQL). It identifies conversion issues and provides guidance for manual fixes.","memory_technique":"SCT = Schema Conversion Tool. Translates your Oracle schema to PostgreSQL — like a database language translator.","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"SCT is equivalent to database migration assessment tools — analysing source database objects and converting them to the target engine's syntax, flagging incompatibilities."},
  {"question_text":"A company needs to implement a solution that provides real-time visibility into their AWS spending with the ability to forecast end-of-month costs. Which combination of services provides this?","options":["AWS Budgets only","AWS Cost Explorer with forecasting + AWS Budgets with alerts + Cost Anomaly Detection","AWS Pricing Calculator only","AWS Trusted Advisor only"],"correct_answer":"AWS Cost Explorer with forecasting + AWS Budgets with alerts + Cost Anomaly Detection","explanation":"Cost Explorer provides visualisation and forecasting. Budgets provides threshold-based alerts. Cost Anomaly Detection provides ML-based unusual spending detection. Together they provide comprehensive real-time cost visibility and proactive alerting.","memory_technique":"Explorer (see) + Budgets (alert) + Anomaly Detection (detect unusual). Three tools for complete cost visibility.","topic_area":"Billing and Pricing","difficulty_level":5,"it_context_mapping":"This combination mirrors enterprise financial monitoring — dashboards for visibility, budget alerts for thresholds, and anomaly detection for unexpected spending patterns."},
  {"question_text":"A company needs to implement a solution that provides automated security response to compromised EC2 instances. The response should isolate the instance, capture forensic evidence, and notify the security team. Which architecture achieves this?","options":["Manual incident response","GuardDuty → EventBridge → Step Functions (isolate via Security Group change + create EBS snapshot + notify via SNS)","CloudWatch Alarm → Lambda → terminate instance","AWS Config → email notification"],"correct_answer":"GuardDuty → EventBridge → Step Functions (isolate via Security Group change + create EBS snapshot + notify via SNS)","explanation":"GuardDuty detects the compromise. EventBridge routes the finding. Step Functions orchestrates the multi-step response: change the Security Group to isolate the instance, create EBS snapshots for forensics, and send SNS notification to the security team.","memory_technique":"Detect (GuardDuty) → Route (EventBridge) → Orchestrate (Step Functions) → Isolate + Snapshot + Notify. Automated incident response playbook.","topic_area":"Security and Compliance","difficulty_level":5,"it_context_mapping":"This is a SOAR (Security Orchestration, Automation, and Response) pattern — automated incident response that isolates threats, preserves evidence, and notifies responders without human intervention."},
  {"question_text":"What is the purpose of AWS Organisations tag policies?","options":["To tag AWS accounts","To define rules for how tags should be used across accounts in an organisation, ensuring consistent tagging for cost allocation and governance","To tag IAM users","To tag security findings"],"correct_answer":"To define rules for how tags should be used across accounts in an organisation, ensuring consistent tagging for cost allocation and governance","explanation":"Tag policies in AWS Organisations define rules for tag keys and allowed values across all accounts. They help maintain consistent tagging standards for cost allocation, automation, and access control.","memory_technique":"Tag policies = Tagging standards enforcer. Ensures everyone uses the same tag keys and values — no more 'Environment' vs 'environment' vs 'env' inconsistencies.","topic_area":"Billing and Pricing","difficulty_level":5,"it_context_mapping":"Tag policies are equivalent to naming conventions and metadata standards in enterprise IT — enforcing consistent labelling across all infrastructure for governance and cost management."},
  {"question_text":"A company needs to implement a solution that provides automated compliance reporting for multiple frameworks (SOC 2, PCI DSS, HIPAA) across 50 AWS accounts. Which architecture is most appropriate?","options":["Manual compliance checks per account","AWS Audit Manager with organisation-wide assessments + AWS Config Aggregator + Security Hub with cross-account findings","AWS Trusted Advisor only","Individual Config Rules per account"],"correct_answer":"AWS Audit Manager with organisation-wide assessments + AWS Config Aggregator + Security Hub with cross-account findings","explanation":"Audit Manager provides framework-specific evidence collection. Config Aggregator provides centralised compliance visibility. Security Hub aggregates security findings across accounts. Together they provide automated, multi-framework compliance reporting at scale.","memory_technique":"Audit Manager (evidence) + Config Aggregator (compliance) + Security Hub (security findings) = Complete compliance automation across all accounts.","topic_area":"Security and Compliance","difficulty_level":5,"it_context_mapping":"This architecture replaces manual compliance evidence collection and GRC tools. It provides the same multi-framework compliance reporting that enterprises achieve with tools like ServiceNow GRC or RSA Archer."},
  {"question_text":"What is the purpose of AWS Compute Optimizer's EBS volume recommendations?","options":["To recommend EBS encryption settings","To analyse EBS volume performance metrics and recommend optimal volume types and sizes to balance performance and cost","To recommend EBS backup schedules","To recommend EBS replication settings"],"correct_answer":"To analyse EBS volume performance metrics and recommend optimal volume types and sizes to balance performance and cost","explanation":"Compute Optimizer analyses EBS volume metrics (IOPS, throughput, latency) and recommends optimal volume types (gp3, io2, etc.) and sizes. It identifies over-provisioned volumes (wasting money) and under-provisioned volumes (risking performance).","memory_technique":"EBS recommendations = Right-size your disks. Compute Optimizer says 'this gp2 volume should be gp3' or 'this 500GB volume only uses 50GB.'","topic_area":"Billing and Pricing","difficulty_level":5,"it_context_mapping":"EBS recommendations are equivalent to storage utilisation reports — identifying over-provisioned LUNs that can be shrunk or moved to cheaper tiers."},
  {"question_text":"A company needs to implement a solution that provides end-to-end encryption for data flowing from IoT devices through Kinesis to S3. Which approach ensures data is encrypted at every stage?","options":["Rely on default AWS encryption only","IoT devices encrypt with KMS data key → Kinesis server-side encryption with KMS → S3 server-side encryption with KMS (SSE-KMS)","Encrypt only at S3","Use VPN for all connections"],"correct_answer":"IoT devices encrypt with KMS data key → Kinesis server-side encryption with KMS → S3 server-side encryption with KMS (SSE-KMS)","explanation":"End-to-end encryption requires encryption at every stage: devices encrypt data before sending (client-side with KMS data key), Kinesis encrypts at rest (server-side with KMS), and S3 encrypts at rest (SSE-KMS). TLS encrypts data in transit between all components.","memory_technique":"End-to-end = Encrypt everywhere. Device (client-side) → Transit (TLS) → Kinesis (SSE-KMS) → Transit (TLS) → S3 (SSE-KMS). No gaps.","topic_area":"Security and Compliance","difficulty_level":5,"it_context_mapping":"End-to-end encryption mirrors defence-in-depth — encrypting data at every layer (application, transport, storage) so that compromise of any single layer doesn't expose plaintext data."},
  {"question_text":"What is the purpose of AWS Organisations backup policies?","options":["To back up AWS Organisations configuration","To centrally manage and apply AWS Backup plans across all accounts in an organisation","To back up IAM policies","To back up billing data"],"correct_answer":"To centrally manage and apply AWS Backup plans across all accounts in an organisation","explanation":"Backup policies in AWS Organisations allow you to centrally create and apply backup plans across all accounts. This ensures consistent data protection across the organisation without configuring backups in each account individually.","memory_technique":"Backup policies = Centralised backup rules for all accounts. Define once at the org level, applied everywhere automatically.","topic_area":"Security and Compliance","difficulty_level":5,"it_context_mapping":"Organisation backup policies are equivalent to enterprise backup policies managed centrally — ensuring all systems across all business units are backed up according to corporate standards."},
  {"question_text":"A company needs to optimise their AWS costs by identifying resources that are running but not being used (zombie resources). Which combination of tools helps identify these?","options":["AWS Budgets only","AWS Trusted Advisor (idle resources) + AWS Compute Optimizer (underutilised) + Cost Explorer (spending trends)","AWS Pricing Calculator","AWS Cost and Usage Report only"],"correct_answer":"AWS Trusted Advisor (idle resources) + AWS Compute Optimizer (underutilised) + Cost Explorer (spending trends)","explanation":"Trusted Advisor identifies idle resources (unused ELBs, unattached EBS volumes, idle EC2 instances). Compute Optimizer identifies underutilised resources that can be right-sized. Cost Explorer shows spending trends to identify growing costs from zombie resources.","memory_technique":"Trusted Advisor (find idle) + Compute Optimizer (find oversized) + Cost Explorer (find trends) = Complete waste elimination toolkit.","topic_area":"Billing and Pricing","difficulty_level":5,"it_context_mapping":"This combination mirrors enterprise IT asset management — identifying unused servers, oversized VMs, and growing costs from resources that should have been decommissioned."},
  {"question_text":"What is the purpose of AWS CloudFormation Change Sets?","options":["To change CloudFormation pricing","To preview the changes CloudFormation will make to your stack before executing them, reducing the risk of unintended changes","To change stack names","To change template formats"],"correct_answer":"To preview the changes CloudFormation will make to your stack before executing them, reducing the risk of unintended changes","explanation":"Change Sets allow you to preview how proposed changes to a stack might impact your running resources before implementing them. You can see which resources will be added, modified, or deleted before executing the change.","memory_technique":"Change Sets = Preview before apply. Like a 'what if' analysis — see what CloudFormation will do before it does it. Reduces surprises.","topic_area":"Technology","difficulty_level":5,"it_context_mapping":"Change Sets are equivalent to Terraform's 'plan' command — showing you what will change before you apply it, reducing the risk of unintended infrastructure modifications."},
  {"question_text":"A company needs to implement a solution that automatically scales their DynamoDB table capacity based on traffic patterns while minimising costs during low-traffic periods. Which approach is most appropriate?","options":["Provisioned capacity with manual scaling","DynamoDB Auto Scaling with target tracking","On-Demand capacity mode for all tables","Provisioned capacity with scheduled scaling only"],"correct_answer":"DynamoDB Auto Scaling with target tracking","explanation":"DynamoDB Auto Scaling with target tracking automatically adjusts provisioned capacity based on actual utilisation. It scales up during traffic spikes and scales down during quiet periods, maintaining a target utilisation percentage (e.g., 70%).","memory_technique":"DynamoDB Auto Scaling = Thermostat for table capacity. Set target utilisation (70%), and capacity adjusts automatically. Cheaper than On-Demand for predictable patterns.","topic_area":"Technology","difficulty_level":5,"it_context_mapping":"DynamoDB Auto Scaling is equivalent to automated capacity management for databases — adjusting resources based on actual demand rather than peak provisioning."},
  {"question_text":"What is the purpose of AWS Organisations AI services opt-out policies?","options":["To opt out of AWS AI services entirely","To prevent AWS from using your content processed by AI services to improve those services","To opt out of AI-based cost recommendations","To disable AI features in your account"],"correct_answer":"To prevent AWS from using your content processed by AI services to improve those services","explanation":"AI services opt-out policies in AWS Organisations allow you to opt out of having your content (processed by services like Lex, Polly, Comprehend) used by AWS to improve and develop the quality of those services. This is important for data privacy compliance.","memory_technique":"AI opt-out = Don't use my data to train your AI. Prevents AWS from using your content to improve their AI services — important for privacy-sensitive organisations.","topic_area":"Security and Compliance","difficulty_level":5,"it_context_mapping":"AI opt-out policies mirror data processing agreements with SaaS vendors — controlling whether your data can be used for the vendor's product improvement purposes."},
  {"question_text":"A company needs to implement a solution that provides automated cost optimisation by automatically purchasing and modifying Reserved Instances and Savings Plans based on usage patterns. Which approach is most appropriate?","options":["Manual RI purchases based on gut feeling","Use Cost Explorer RI/SP recommendations + implement automated purchasing via AWS APIs with approval workflows","Buy all On-Demand and never commit","Purchase maximum RIs for all instance types"],"correct_answer":"Use Cost Explorer RI/SP recommendations + implement automated purchasing via AWS APIs with approval workflows","explanation":"Cost Explorer provides data-driven recommendations. Automated purchasing via AWS APIs (with approval workflows for governance) ensures commitments are continuously optimised as usage patterns change. This balances cost savings with governance.","memory_technique":"Recommendations (data) + Automation (action) + Approval (governance) = Continuous cost optimisation. Not set-and-forget — continuously adapt commitments to usage.","topic_area":"Billing and Pricing","difficulty_level":5,"it_context_mapping":"This mirrors enterprise procurement automation — using data-driven recommendations with approval workflows to continuously optimise volume commitments as business needs change."},
  {"question_text":"What is the purpose of AWS Trusted Advisor's fault tolerance checks?","options":["To check for software faults","To identify single points of failure and recommend redundancy improvements like Multi-AZ deployments and backup configurations","To check for network faults","To check for billing faults"],"correct_answer":"To identify single points of failure and recommend redundancy improvements like Multi-AZ deployments and backup configurations","explanation":"Trusted Advisor's Fault Tolerance checks identify resources that lack redundancy — such as RDS instances without Multi-AZ, EBS volumes without recent snapshots, or Auto Scaling groups with instances in only one AZ.","memory_technique":"Fault Tolerance checks = Single point of failure finder. Trusted Advisor says 'this RDS has no standby' or 'this ASG is in only one AZ.'","topic_area":"Cloud Concepts","difficulty_level":4,"it_context_mapping":"Fault tolerance checks are equivalent to DR readiness assessments — identifying infrastructure components that would cause outages if they failed."},
  {"question_text":"What is the purpose of AWS Health API?","options":["A healthcare API","A programmatic interface to AWS Health events that enables automated responses to service disruptions affecting your resources","A health monitoring API for EC2","A billing health API"],"correct_answer":"A programmatic interface to AWS Health events that enables automated responses to service disruptions affecting your resources","explanation":"The AWS Health API provides programmatic access to AWS Health events. You can use it with EventBridge to automatically respond to events — such as triggering failover when an AZ is impaired or notifying teams about upcoming maintenance.","memory_technique":"Health API = Programmatic access to AWS health events. Automate responses to AWS outages — like an automated DR trigger.","topic_area":"Cloud Concepts","difficulty_level":4,"it_context_mapping":"The Health API is equivalent to programmatic access to a monitoring system's event feed — enabling automated incident response workflows triggered by infrastructure events."},
  {"question_text":"What is the purpose of AWS Compute Optimizer's Lambda function recommendations?","options":["To recommend Lambda pricing","To analyse Lambda function invocation patterns and recommend optimal memory configurations for cost and performance","To recommend Lambda layers","To recommend Lambda runtimes"],"correct_answer":"To analyse Lambda function invocation patterns and recommend optimal memory configurations for cost and performance","explanation":"Compute Optimizer analyses Lambda function metrics (invocation count, duration, memory utilisation) and recommends optimal memory configurations. Since Lambda CPU scales with memory, right-sizing memory optimises both performance and cost.","memory_technique":"Lambda recommendations = Right-size your function memory. More memory = more CPU = faster execution but higher cost. Find the sweet spot.","topic_area":"Billing and Pricing","difficulty_level":4,"it_context_mapping":"Lambda memory recommendations are equivalent to application performance tuning — finding the optimal resource allocation that balances execution speed and cost."},
  {"question_text":"What is the purpose of Amazon S3 Storage Lens?","options":["A lens for viewing S3 objects","An analytics service that provides organisation-wide visibility into S3 storage usage, activity trends, and cost optimisation recommendations","A data visualisation service","A storage monitoring service"],"correct_answer":"An analytics service that provides organisation-wide visibility into S3 storage usage, activity trends, and cost optimisation recommendations","explanation":"S3 Storage Lens provides organisation-wide visibility into object storage usage and activity trends. It delivers metrics, dashboards, and recommendations to help optimise storage costs and apply data protection best practices.","memory_technique":"Storage Lens = Magnifying glass for S3. See usage patterns, find cost savings, identify data protection gaps across all your buckets.","topic_area":"Billing and Pricing","difficulty_level":4,"it_context_mapping":"S3 Storage Lens is equivalent to storage analytics tools that provide visibility into file server usage — identifying stale data, growth trends, and optimisation opportunities."},
  {"question_text":"What is the purpose of AWS Graviton-based instances for cost optimisation?","options":["They are more expensive than x86","They provide up to 40% better price-performance than comparable x86 instances for compatible workloads","They are only for HPC","They require special operating systems"],"correct_answer":"They provide up to 40% better price-performance than comparable x86 instances for compatible workloads","explanation":"AWS Graviton processors (ARM-based) provide up to 40% better price-performance than comparable x86 instances. Most Linux workloads run without modification on Graviton, making it a straightforward cost optimisation for compatible applications.","memory_technique":"Graviton = Same workload, lower cost. ARM-based, 40% better price-performance. If your app runs on Linux, try Graviton.","topic_area":"Billing and Pricing","difficulty_level":4,"it_context_mapping":"Graviton adoption is equivalent to the ARM transition in data centers — moving compatible workloads to more efficient processors for cost savings without application changes."},
  {"question_text":"What is the purpose of AWS Billing Conductor?","options":["A billing automation tool","A service that allows you to customise your billing data to create custom pricing and cost visibility for your organisation's accounts","A payment processing service","A billing dispute service"],"correct_answer":"A service that allows you to customise your billing data to create custom pricing and cost visibility for your organisation's accounts","explanation":"AWS Billing Conductor allows you to create custom billing groups, apply custom pricing rates, and generate custom Cost and Usage Reports. It's useful for MSPs and organisations that need to show different pricing to different business units.","memory_technique":"Billing Conductor = Custom billing orchestrator. Create custom pricing views — like a reseller margin tool or internal chargeback system.","topic_area":"Billing and Pricing","difficulty_level":4,"it_context_mapping":"Billing Conductor is equivalent to a billing mediation platform used by MSPs — applying custom margins and creating custom invoices for different customers from a single AWS bill."},
  {"question_text":"What is the purpose of AWS CloudWatch Application Insights?","options":["To monitor application code quality","To automatically detect and diagnose application health issues using ML, providing correlated findings across application components","To monitor application security","To monitor application costs"],"correct_answer":"To automatically detect and diagnose application health issues using ML, providing correlated findings across application components","explanation":"CloudWatch Application Insights uses ML to automatically detect application health issues. It correlates findings across application components (EC2, RDS, ELB) to identify root causes and reduce mean time to resolution.","memory_technique":"Application Insights = AI doctor for your app. Automatically detects problems and correlates symptoms across components to find the root cause.","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"Application Insights is equivalent to AI-powered APM tools that correlate events across infrastructure layers to identify root causes — reducing manual troubleshooting time."},
  {"question_text":"What is the purpose of Amazon DevOps Guru?","options":["A DevOps training service","An ML-powered service that identifies operational issues, predicts impending problems, and recommends remediation actions","A code review service","A deployment service"],"correct_answer":"An ML-powered service that identifies operational issues, predicts impending problems, and recommends remediation actions","explanation":"Amazon DevOps Guru uses ML to identify operational issues and predict impending problems before they impact users. It analyses CloudWatch metrics, Config changes, and CloudTrail events to detect anomalies and provide actionable recommendations.","memory_technique":"DevOps Guru = AI operations expert. Predicts problems before they happen and tells you how to fix them — like a crystal ball for ops.","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"DevOps Guru is equivalent to AIOps platforms like Moogsoft or BigPanda — using ML to detect anomalies, correlate events, and predict incidents before they impact users."},
]

