questions += [
  {"question_text":"What is AWS CloudShell?","options":["A desktop application","A browser-based shell environment pre-authenticated with your console credentials for running AWS CLI commands","A mobile app","A terminal emulator"],"correct_answer":"A browser-based shell environment pre-authenticated with your console credentials for running AWS CLI commands","explanation":"AWS CloudShell is a browser-based shell available from the AWS Management Console. It comes pre-installed with AWS CLI, Python, Node.js, and other tools, and is automatically authenticated with your console credentials.","memory_technique":"CloudShell = Terminal in your browser. Pre-authenticated, pre-installed tools. No setup needed.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"CloudShell is equivalent to Azure Cloud Shell or Google Cloud Shell — a browser-based terminal for quick CLI tasks without installing anything locally."},
  {"question_text":"What is AWS Config conformance packs?","options":["Packages of EC2 configurations","Collections of AWS Config rules and remediation actions that can be deployed as a single entity across accounts","Packages of IAM policies","Packages of CloudFormation templates"],"correct_answer":"Collections of AWS Config rules and remediation actions that can be deployed as a single entity across accounts","explanation":"Conformance packs are collections of Config rules and remediation actions that can be deployed together. AWS provides sample packs for common frameworks (CIS, PCI DSS, NIST) and you can create custom packs.","memory_technique":"Conformance pack = Compliance bundle. Deploy a whole set of compliance rules at once — like installing a compliance plugin.","topic_area":"Security and Compliance","difficulty_level":3,"it_context_mapping":"Conformance packs are equivalent to compliance policy bundles in GRC tools — pre-packaged sets of checks for specific regulatory frameworks."},
  {"question_text":"What is the purpose of Amazon Managed Blockchain?","options":["A cryptocurrency mining service","A fully managed service for creating and managing blockchain networks using Hyperledger Fabric or Ethereum","A financial trading service","A distributed database service"],"correct_answer":"A fully managed service for creating and managing blockchain networks using Hyperledger Fabric or Ethereum","explanation":"Amazon Managed Blockchain is a fully managed service that makes it easy to create and manage scalable blockchain networks using Hyperledger Fabric or Ethereum, without managing the underlying infrastructure.","memory_technique":"Managed Blockchain = Blockchain without the ops. Create and manage blockchain networks — AWS handles the infrastructure.","topic_area":"Technology","difficulty_level":3,"it_context_mapping":"Managed Blockchain replaces self-managed blockchain nodes. It provides the same distributed ledger capabilities without managing peer nodes, ordering services, and certificate authorities."},
  {"question_text":"What is the purpose of AWS Chatbot?","options":["A customer service chatbot","An interactive agent that enables ChatOps by sending AWS notifications to Slack and Microsoft Teams channels and running commands","A conversational AI service","A virtual assistant"],"correct_answer":"An interactive agent that enables ChatOps by sending AWS notifications to Slack and Microsoft Teams channels and running commands","explanation":"AWS Chatbot integrates with Slack and Microsoft Teams to deliver AWS notifications (CloudWatch alarms, Security Hub findings, Budgets alerts) and allows you to run AWS CLI commands directly from chat channels.","memory_technique":"AWS Chatbot = AWS in your Slack/Teams. Get alerts and run commands without leaving your chat app — ChatOps for AWS.","topic_area":"Technology","difficulty_level":3,"it_context_mapping":"AWS Chatbot is equivalent to ChatOps tools like PagerDuty or Opsgenie Slack integrations — bringing operational alerts and actions into team communication channels."},
  {"question_text":"What is the purpose of AWS Elemental MediaConvert?","options":["A media player service","A file-based video transcoding service for creating video-on-demand content","A live streaming service","A media storage service"],"correct_answer":"A file-based video transcoding service for creating video-on-demand content","explanation":"AWS Elemental MediaConvert is a file-based video transcoding service that processes video files for on-demand delivery. It supports a wide range of input and output formats and provides broadcast-grade features.","memory_technique":"MediaConvert = Video format factory. Input video in any format → output in any format for any device. Broadcast quality.","topic_area":"Technology","difficulty_level":3,"it_context_mapping":"MediaConvert replaces on-premises video transcoding farms. It provides the same broadcast-grade transcoding capabilities without managing encoding hardware."},
  {"question_text":"What is the purpose of AWS Elemental MediaLive?","options":["A video-on-demand service","A real-time video encoding service for creating live video streams","A media storage service","A video editing service"],"correct_answer":"A real-time video encoding service for creating live video streams","explanation":"AWS Elemental MediaLive is a real-time video encoding service that creates high-quality live video streams for delivery to broadcast televisions and internet-connected devices.","memory_technique":"MediaLive = Live video encoder. Real-time encoding for live streams — sports, news, events.","topic_area":"Technology","difficulty_level":3,"it_context_mapping":"MediaLive replaces on-premises live encoding hardware. It provides the same real-time video encoding capabilities without managing encoding appliances."},
  {"question_text":"What is the purpose of AWS IoT Greengrass?","options":["A lawn care IoT service","A service that extends AWS to edge devices so they can act locally on the data they generate while using the cloud for management and analytics","An IoT device marketplace","A green energy monitoring service"],"correct_answer":"A service that extends AWS to edge devices so they can act locally on the data they generate while using the cloud for management and analytics","explanation":"AWS IoT Greengrass extends AWS to edge devices so they can act locally on data they generate, while still using the cloud for management, analytics, and durable storage. It enables local compute, messaging, and ML inference at the edge.","memory_technique":"Greengrass = AWS at the edge. Run Lambda functions and ML models on IoT devices — process data locally, sync with cloud.","topic_area":"Technology","difficulty_level":3,"it_context_mapping":"Greengrass is equivalent to edge computing platforms that run application logic on local gateways — processing data at the source before sending summaries to the cloud."},
  {"question_text":"What is the purpose of Amazon Kendra?","options":["A search engine for the internet","An intelligent enterprise search service powered by ML that provides natural language search across enterprise data","A web crawler service","A database search service"],"correct_answer":"An intelligent enterprise search service powered by ML that provides natural language search across enterprise data","explanation":"Amazon Kendra is an intelligent search service powered by machine learning. It provides natural language search capabilities across enterprise data sources like S3, SharePoint, databases, and file systems.","memory_technique":"Kendra = Enterprise Google. Natural language search across all your company's data — documents, wikis, databases.","topic_area":"Technology","difficulty_level":3,"it_context_mapping":"Kendra replaces traditional enterprise search tools like Elasticsearch or SharePoint Search. It provides ML-powered relevance ranking and natural language understanding."},
  {"question_text":"What is the purpose of AWS License Manager?","options":["To manage AWS service licences","To manage, discover, and report on software licence usage across AWS and on-premises environments","To purchase software licences","To manage open-source licences"],"correct_answer":"To manage, discover, and report on software licence usage across AWS and on-premises environments","explanation":"AWS License Manager helps you manage software licences from vendors like Microsoft, SAP, and Oracle across AWS and on-premises environments. It tracks licence usage, enforces limits, and reduces the risk of non-compliance.","memory_technique":"License Manager = Software licence tracker. Know how many licences you're using vs. how many you own — avoid compliance violations.","topic_area":"Cloud Concepts","difficulty_level":3,"it_context_mapping":"License Manager is equivalent to software asset management (SAM) tools like Flexera or Snow — tracking licence consumption to ensure compliance and optimise spending."},
  {"question_text":"What is the purpose of AWS Marketplace Private Marketplace?","options":["A marketplace for private data","A curated subset of AWS Marketplace products approved by your organisation for procurement governance","A private shopping experience","A marketplace for internal tools"],"correct_answer":"A curated subset of AWS Marketplace products approved by your organisation for procurement governance","explanation":"Private Marketplace allows administrators to create a curated catalogue of approved AWS Marketplace products. Users can only procure products from this approved list, ensuring governance and compliance with procurement policies.","memory_technique":"Private Marketplace = Approved vendor list. Only pre-approved software can be purchased — procurement governance for cloud.","topic_area":"Cloud Concepts","difficulty_level":3,"it_context_mapping":"Private Marketplace is equivalent to an approved software catalogue in enterprise procurement — users can only purchase from pre-vetted vendors and products."},
  {"question_text":"What is the purpose of AWS Well-Architected Lenses?","options":["Physical lenses for viewing AWS infrastructure","Domain-specific extensions of the Well-Architected Framework that provide additional best practices for specific workload types","Monitoring lenses for CloudWatch","Security scanning lenses"],"correct_answer":"Domain-specific extensions of the Well-Architected Framework that provide additional best practices for specific workload types","explanation":"Well-Architected Lenses are domain-specific extensions that provide additional best practices beyond the core framework. Examples include the Serverless Lens, SaaS Lens, Machine Learning Lens, and IoT Lens.","memory_technique":"Lenses = Specialised views. The core framework is the base; lenses add domain-specific guidance for serverless, SaaS, ML, etc.","topic_area":"Cloud Concepts","difficulty_level":3,"it_context_mapping":"Well-Architected Lenses are equivalent to industry-specific architecture frameworks — providing specialised guidance beyond general best practices for specific workload types."},
  {"question_text":"What is the purpose of AWS Outposts pricing model?","options":["Pay per hour like EC2","Pay a fixed monthly fee for the Outposts rack with no upfront cost, including hardware, delivery, installation, and maintenance","Pay per GB stored","Pay per API call"],"correct_answer":"Pay a fixed monthly fee for the Outposts rack with no upfront cost, including hardware, delivery, installation, and maintenance","explanation":"AWS Outposts uses a subscription pricing model — you pay a fixed monthly fee that includes the hardware, delivery, installation, maintenance, and software. There are no upfront costs. You choose the configuration and commit to a 3-year term.","memory_technique":"Outposts = Monthly subscription for AWS hardware in your building. Fixed fee, no upfront cost, 3-year term. AWS maintains it.","topic_area":"Billing and Pricing","difficulty_level":3,"it_context_mapping":"Outposts pricing mirrors hardware-as-a-service models like HPE GreenLake or Dell APEX — subscription-based on-premises infrastructure with vendor maintenance included."},
  {"question_text":"What is the purpose of AWS Wavelength pricing?","options":["Special pricing for 5G services","Same EC2 and EBS pricing as the parent Region, plus carrier gateway data processing charges","Free for all customers","Premium pricing for all services"],"correct_answer":"Same EC2 and EBS pricing as the parent Region, plus carrier gateway data processing charges","explanation":"Wavelength Zone pricing uses the same EC2 and EBS rates as the parent Region. Additional charges apply for data processed through the carrier gateway (connecting to the carrier network) and data transfer between the Wavelength Zone and the parent Region.","memory_technique":"Wavelength pricing = Same as Region + carrier gateway fees. The compute is the same price; you pay extra for the 5G network connection.","topic_area":"Billing and Pricing","difficulty_level":3,"it_context_mapping":"Wavelength pricing mirrors edge computing pricing — standard compute costs plus additional fees for the specialised network connectivity (5G carrier network access)."},
  {"question_text":"What is the purpose of AWS Local Zones pricing?","options":["Discounted pricing for local development","Same pricing as the parent Region for most services, with some services having slightly higher rates","Free for all customers","Premium pricing for all services"],"correct_answer":"Same pricing as the parent Region for most services, with some services having slightly higher rates","explanation":"Local Zones generally use the same pricing as the parent Region for EC2, EBS, and other services. Some services may have slightly different rates. Data transfer between a Local Zone and its parent Region is charged.","memory_technique":"Local Zones pricing = Mostly same as Region. Some services slightly more expensive. Data transfer to parent Region costs money.","topic_area":"Billing and Pricing","difficulty_level":3,"it_context_mapping":"Local Zone pricing mirrors edge data center pricing — similar to core data center rates with small premiums for the edge location and inter-site data transfer charges."},
  {"question_text":"A company needs to implement a solution that provides automated patch management for their EC2 fleet across multiple accounts. Which service provides this?","options":["AWS Config","AWS Systems Manager Patch Manager with Organisation-wide patching","Amazon Inspector","AWS CloudFormation"],"correct_answer":"AWS Systems Manager Patch Manager with Organisation-wide patching","explanation":"Systems Manager Patch Manager automates the process of patching managed instances. With AWS Organisations integration, you can define patching policies centrally and apply them across all accounts, ensuring consistent patch compliance.","memory_technique":"Patch Manager = Automated Windows Update for your fleet. Define patch baselines, schedule maintenance windows, patch across all accounts.","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"Patch Manager replaces WSUS (Windows Server Update Services) and manual patching processes. It provides the same automated patching capabilities across both Windows and Linux fleets."},
  {"question_text":"What is the purpose of AWS Systems Manager Session Manager?","options":["To manage user sessions","To provide secure, auditable shell access to EC2 instances without opening SSH/RDP ports or managing SSH keys","To manage database sessions","To manage application sessions"],"correct_answer":"To provide secure, auditable shell access to EC2 instances without opening SSH/RDP ports or managing SSH keys","explanation":"Session Manager provides secure shell access to EC2 instances through the AWS console or CLI without needing to open inbound ports, manage SSH keys, or use bastion hosts. All sessions are logged to CloudTrail and optionally to S3/CloudWatch.","memory_technique":"Session Manager = SSH without SSH. No open ports, no keys, full audit trail. Access instances through the AWS console securely.","topic_area":"Security and Compliance","difficulty_level":4,"it_context_mapping":"Session Manager replaces bastion hosts and SSH key management. It provides the same remote access capability with better security (no open ports) and full audit logging."},
  {"question_text":"What is the purpose of AWS Systems Manager Automation?","options":["To automate billing","To create and run automation documents (runbooks) that perform common maintenance and deployment tasks on AWS resources","To automate IAM user creation","To automate S3 bucket creation only"],"correct_answer":"To create and run automation documents (runbooks) that perform common maintenance and deployment tasks on AWS resources","explanation":"Systems Manager Automation allows you to create runbooks that automate common operational tasks — like patching AMIs, creating snapshots, remediating Config findings, or performing rolling updates across a fleet.","memory_technique":"SSM Automation = Runbook automation. Define steps in a document, execute across your fleet. Like Ansible playbooks but managed by AWS.","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"SSM Automation is equivalent to Ansible playbooks or Puppet tasks — automated runbooks for common operational procedures that can be triggered manually or by events."},
  {"question_text":"What is the purpose of AWS CloudFormation StackSets?","options":["To create nested stacks","To deploy CloudFormation stacks across multiple AWS accounts and regions with a single operation","To create stack templates","To manage stack dependencies"],"correct_answer":"To deploy CloudFormation stacks across multiple AWS accounts and regions with a single operation","explanation":"CloudFormation StackSets extend stacks by enabling you to create, update, or delete stacks across multiple accounts and regions with a single operation. This is essential for deploying consistent infrastructure across an AWS Organisation.","memory_technique":"StackSets = Deploy everywhere at once. One template, many accounts, many regions. Like a mass deployment tool for CloudFormation.","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"StackSets are equivalent to deploying configuration changes across multiple data centers simultaneously — one change propagated to all environments."},
  {"question_text":"What is the purpose of Amazon EventBridge Pipes?","options":["Network pipes between VPCs","A serverless service for connecting event sources to targets with optional filtering, enrichment, and transformation","Data pipeline service","Log streaming pipes"],"correct_answer":"A serverless service for connecting event sources to targets with optional filtering, enrichment, and transformation","explanation":"EventBridge Pipes provides point-to-point integrations between event sources (SQS, Kinesis, DynamoDB Streams) and targets (Lambda, Step Functions, API destinations) with optional filtering, enrichment, and transformation — without writing integration code.","memory_technique":"EventBridge Pipes = Plumbing between services. Connect source → filter → enrich → transform → target. No code needed.","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"EventBridge Pipes replaces custom integration code (Lambda functions that poll queues and forward events). It provides declarative point-to-point event routing."},
  {"question_text":"What is the purpose of AWS Application Composer?","options":["A music composition service","A visual tool for designing and building serverless applications by dragging and dropping AWS services","A document composition service","A container composition service"],"correct_answer":"A visual tool for designing and building serverless applications by dragging and dropping AWS services","explanation":"AWS Application Composer is a visual builder for serverless applications. You drag and drop AWS services, connect them visually, and it generates the CloudFormation/SAM template automatically.","memory_technique":"Application Composer = Visual serverless builder. Drag, drop, connect — generates IaC automatically. Like a visual programming tool for cloud architecture.","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"Application Composer is equivalent to visual workflow designers in low-code platforms — providing a graphical interface for designing application architectures that generates code automatically."},
  {"question_text":"What is the purpose of AWS Clean Rooms?","options":["A data center cleaning service","A service that helps companies analyse their combined datasets without sharing raw data with each other","A data sanitisation service","A room booking service"],"correct_answer":"A service that helps companies analyse their combined datasets without sharing raw data with each other","explanation":"AWS Clean Rooms allows companies to create secure data collaboration environments where multiple parties can query their combined datasets without exposing the underlying raw data to each other.","memory_technique":"Clean Rooms = Collaborate on data without sharing it. Multiple companies query combined data — nobody sees the other's raw data.","topic_area":"Security and Compliance","difficulty_level":5,"it_context_mapping":"Clean Rooms is equivalent to secure multi-party computation or data clean room solutions used in advertising and healthcare — enabling data collaboration while preserving privacy."},
  {"question_text":"What is the purpose of AWS Verified Access?","options":["A service for verifying AWS account ownership","A zero-trust service that provides secure access to corporate applications without a VPN by verifying user identity and device security posture","A certificate verification service","An identity verification service"],"correct_answer":"A zero-trust service that provides secure access to corporate applications without a VPN by verifying user identity and device security posture","explanation":"AWS Verified Access provides secure access to corporate applications without requiring a VPN. It verifies each access request against identity (who you are) and device posture (is your device compliant) policies before granting access.","memory_technique":"Verified Access = VPN replacement. Zero-trust access to apps — verify identity + device health for every request. No VPN tunnel needed.","topic_area":"Security and Compliance","difficulty_level":5,"it_context_mapping":"Verified Access is equivalent to ZTNA (Zero Trust Network Access) solutions like Zscaler Private Access or Cloudflare Access — replacing VPNs with identity-aware application access."},
  {"question_text":"What is the purpose of Amazon Security Lake?","options":["A data lake for storing any data","A service that automatically centralises security data from AWS and third-party sources into a purpose-built security data lake using the OCSF format","A lake for storing encryption keys","A backup lake for security logs"],"correct_answer":"A service that automatically centralises security data from AWS and third-party sources into a purpose-built security data lake using the OCSF format","explanation":"Amazon Security Lake automatically centralises security data from AWS services, SaaS providers, and third-party sources into a purpose-built data lake. It normalises data to the Open Cybersecurity Schema Framework (OCSF) for consistent analysis.","memory_technique":"Security Lake = Central security data lake. All security logs normalised to one format (OCSF) in one place. Query everything consistently.","topic_area":"Security and Compliance","difficulty_level":5,"it_context_mapping":"Security Lake is equivalent to a centralised SIEM data lake — aggregating and normalising security logs from all sources for unified threat detection and investigation."},
  {"question_text":"What is the purpose of AWS Signer?","options":["A document signing service","A fully managed code signing service that ensures the trust and integrity of your code by digitally signing code packages","An email signing service","A certificate signing service"],"correct_answer":"A fully managed code signing service that ensures the trust and integrity of your code by digitally signing code packages","explanation":"AWS Signer is a fully managed code signing service that ensures the trust and integrity of your code. It signs Lambda deployment packages, IoT firmware, and container images to verify they haven't been tampered with.","memory_technique":"AWS Signer = Code notary. Digitally signs your code to prove it hasn't been tampered with — like a wax seal on a letter.","topic_area":"Security and Compliance","difficulty_level":5,"it_context_mapping":"AWS Signer is equivalent to code signing certificates used in software distribution — ensuring that deployed code is authentic and hasn't been modified since it was signed by the publisher."},
  {"question_text":"What is the purpose of Amazon CodeWhisperer (now Amazon Q Developer)?","options":["A code review service","An AI-powered code generation service that provides real-time code suggestions and security scanning in your IDE","A code deployment service","A code testing service"],"correct_answer":"An AI-powered code generation service that provides real-time code suggestions and security scanning in your IDE","explanation":"Amazon Q Developer (formerly CodeWhisperer) is an AI-powered coding companion that generates code suggestions in real-time based on your comments and existing code. It also scans code for security vulnerabilities.","memory_technique":"Q Developer = AI pair programmer. Suggests code as you type, scans for security issues. Like GitHub Copilot but from AWS.","topic_area":"Technology","difficulty_level":5,"it_context_mapping":"Q Developer is equivalent to AI coding assistants like GitHub Copilot — providing ML-powered code completion and generation to accelerate development."},
  {"question_text":"What is the purpose of AWS HealthOmics?","options":["A healthcare billing service","A service for storing, querying, and analysing genomic and other omics data at scale","A health monitoring service","A medical records service"],"correct_answer":"A service for storing, querying, and analysing genomic and other omics data at scale","explanation":"AWS HealthOmics is a purpose-built service for storing, querying, and analysing genomic, transcriptomic, and other omics data. It provides specialised storage and compute for bioinformatics workflows.","memory_technique":"HealthOmics = Genomics data platform. Store and analyse DNA/RNA data at scale — purpose-built for bioinformatics.","topic_area":"Technology","difficulty_level":5,"it_context_mapping":"HealthOmics replaces custom bioinformatics pipelines on HPC clusters. It provides managed storage and compute optimised for genomic data analysis."},
  {"question_text":"What is the purpose of AWS SimSpace Weaver?","options":["A web development framework","A managed service for running large-scale spatial simulations across multiple EC2 instances","A space exploration service","A virtual reality service"],"correct_answer":"A managed service for running large-scale spatial simulations across multiple EC2 instances","explanation":"AWS SimSpace Weaver is a managed service for running large-scale spatial simulations. It distributes simulation workloads across multiple EC2 instances, enabling simulations with millions of entities.","memory_technique":"SimSpace Weaver = Massive simulation engine. Weaves together multiple servers to run huge simulations — cities, crowds, physics.","topic_area":"Technology","difficulty_level":5,"it_context_mapping":"SimSpace Weaver replaces custom distributed simulation frameworks. It provides managed infrastructure for large-scale simulations that would otherwise require complex cluster management."},
  {"question_text":"What is the purpose of AWS Supply Chain?","options":["A service for managing AWS hardware supply","A cloud application that helps organisations build more resilient and sustainable supply chains with ML-powered insights","A logistics service","A procurement service"],"correct_answer":"A cloud application that helps organisations build more resilient and sustainable supply chains with ML-powered insights","explanation":"AWS Supply Chain is a cloud application that provides ML-powered insights to help organisations improve supply chain visibility, reduce risks, and optimise inventory levels.","memory_technique":"AWS Supply Chain = ML-powered supply chain visibility. Predict disruptions, optimise inventory, improve resilience.","topic_area":"Technology","difficulty_level":5,"it_context_mapping":"AWS Supply Chain is equivalent to supply chain management platforms like SAP IBP or Kinaxis — providing demand forecasting, inventory optimisation, and risk management."},
  {"question_text":"What is the purpose of AWS Entity Resolution?","options":["A DNS resolution service","A service that helps match and link related records across multiple data sources without sharing raw data","A conflict resolution service","A name resolution service"],"correct_answer":"A service that helps match and link related records across multiple data sources without sharing raw data","explanation":"AWS Entity Resolution helps you match and link related records stored across multiple applications, channels, and data stores. It uses ML-based matching techniques to identify records that refer to the same entity.","memory_technique":"Entity Resolution = Record matching service. Find that 'John Smith' in database A is the same person as 'J. Smith' in database B.","topic_area":"Technology","difficulty_level":5,"it_context_mapping":"Entity Resolution is equivalent to master data management (MDM) matching engines — identifying duplicate or related records across disparate systems to create a unified view."},
  {"question_text":"What is the purpose of AWS Payment Cryptography?","options":["A cryptocurrency service","A managed service for payment HSM operations like PIN translation, card verification, and key management for payment processing","A billing encryption service","A payment gateway"],"correct_answer":"A managed service for payment HSM operations like PIN translation, card verification, and key management for payment processing","explanation":"AWS Payment Cryptography is a managed service that provides payment HSM functionality — PIN translation, card verification values (CVV), and cryptographic key management — without managing physical payment HSMs.","memory_technique":"Payment Cryptography = Managed payment HSM. PIN translation, card verification, key management — all the crypto operations payment processors need.","topic_area":"Security and Compliance","difficulty_level":5,"it_context_mapping":"Payment Cryptography replaces physical payment HSMs (like Thales payShield) used by banks and payment processors. It provides the same PCI-compliant cryptographic operations as a managed service."},
  {"question_text":"What is the purpose of Amazon Bedrock?","options":["A foundation for building data centers","A fully managed service for building generative AI applications using foundation models from multiple providers","A database service","A compute service"],"correct_answer":"A fully managed service for building generative AI applications using foundation models from multiple providers","explanation":"Amazon Bedrock is a fully managed service that provides access to foundation models (FMs) from AI companies like Anthropic, Meta, Stability AI, and Amazon through a single API. It enables building generative AI applications without managing infrastructure.","memory_technique":"Bedrock = Foundation for AI apps. Access multiple AI models (Claude, Llama, Titan) through one API — no ML infrastructure to manage.","topic_area":"Technology","difficulty_level":5,"it_context_mapping":"Bedrock is equivalent to a managed AI model marketplace — providing access to multiple foundation models through a unified API, similar to Azure OpenAI Service or Google Vertex AI."},
  {"question_text":"What is the purpose of Amazon Q Business?","options":["A business intelligence service","A generative AI assistant that can answer questions, provide summaries, and generate content based on your enterprise data","A business process service","A business analytics service"],"correct_answer":"A generative AI assistant that can answer questions, provide summaries, and generate content based on your enterprise data","explanation":"Amazon Q Business is a generative AI-powered assistant that connects to your enterprise data sources and provides answers, summaries, and content generation based on your organisation's information — with built-in access controls.","memory_technique":"Q Business = ChatGPT for your company data. Ask questions about your internal docs, wikis, and databases — with proper access controls.","topic_area":"Technology","difficulty_level":5,"it_context_mapping":"Amazon Q Business is equivalent to enterprise AI assistants like Microsoft Copilot for M365 — providing generative AI capabilities grounded in your organisation's data with identity-aware access controls."},
]

