questions += [
  {"question_text":"What is the purpose of AWS Wickr?","options":["A web development framework","An end-to-end encrypted messaging and collaboration service for enterprises","A network monitoring service","A ticketing service"],"correct_answer":"An end-to-end encrypted messaging and collaboration service for enterprises","explanation":"AWS Wickr is an end-to-end encrypted messaging service that enables secure communication through messaging, voice calls, video calls, and file sharing with administrative controls and data retention capabilities.","memory_technique":"Wickr = Encrypted enterprise messaging. End-to-end encrypted comms with admin controls — like Signal for businesses.","topic_area":"Security and Compliance","difficulty_level":3,"it_context_mapping":"Wickr is equivalent to enterprise-grade encrypted messaging platforms — providing the security of end-to-end encryption with the compliance features (retention, admin controls) enterprises require."},
  {"question_text":"What is the purpose of AWS HealthImaging?","options":["A general image storage service","A HIPAA-eligible service for storing, accessing, and analysing medical imaging data at scale","A photo editing service","A medical diagnosis service"],"correct_answer":"A HIPAA-eligible service for storing, accessing, and analysing medical imaging data at scale","explanation":"AWS HealthImaging is a HIPAA-eligible service purpose-built for storing, accessing, and analysing medical imaging data (DICOM). It provides sub-second image retrieval and integrates with healthcare applications.","memory_technique":"HealthImaging = Medical image vault. DICOM storage with fast retrieval — purpose-built for radiology and medical imaging.","topic_area":"Technology","difficulty_level":3,"it_context_mapping":"HealthImaging replaces on-premises PACS (Picture Archiving and Communication Systems) for medical image storage — providing the same DICOM capabilities in a managed, scalable cloud service."},
  {"question_text":"What is the purpose of AWS Mainframe Modernization?","options":["A service for running mainframes on AWS","A set of tools and services for migrating and modernising mainframe applications to AWS","A mainframe monitoring service","A mainframe backup service"],"correct_answer":"A set of tools and services for migrating and modernising mainframe applications to AWS","explanation":"AWS Mainframe Modernization provides tools for migrating mainframe workloads to AWS. It supports both replatforming (running COBOL on AWS) and refactoring (converting to modern languages) approaches.","memory_technique":"Mainframe Modernization = Escape the mainframe. Migrate COBOL apps to AWS — either run them as-is or convert to modern code.","topic_area":"Technology","difficulty_level":3,"it_context_mapping":"Mainframe Modernization addresses the challenge of legacy mainframe migration — providing tools equivalent to Micro Focus or LzLabs for running or converting mainframe workloads."},
  {"question_text":"What is the purpose of AWS Data Exchange?","options":["A data transfer service","A service for finding, subscribing to, and using third-party data in the cloud","A database exchange service","A file sharing service"],"correct_answer":"A service for finding, subscribing to, and using third-party data in the cloud","explanation":"AWS Data Exchange makes it easy to find, subscribe to, and use third-party data in the cloud. Data providers publish datasets; subscribers access them directly in their AWS accounts.","memory_technique":"Data Exchange = Data marketplace. Subscribe to third-party datasets (weather, financial, demographic) and use them directly in AWS.","topic_area":"Technology","difficulty_level":2,"it_context_mapping":"Data Exchange is equivalent to data marketplace platforms — providing a catalogue of third-party datasets that can be integrated into your analytics pipelines."},
  {"question_text":"What is the purpose of AWS AppConfig?","options":["A service for configuring mobile apps","A feature of Systems Manager for deploying application configuration changes safely with validation and rollback","A service for configuring EC2 instances","A service for configuring databases"],"correct_answer":"A feature of Systems Manager for deploying application configuration changes safely with validation and rollback","explanation":"AWS AppConfig (part of Systems Manager) enables you to deploy application configuration changes independently from code deployments. It supports validation, gradual rollout, and automatic rollback if errors are detected.","memory_technique":"AppConfig = Feature flags and config deployment. Change app behaviour without deploying code — with safety nets (validation, rollback).","topic_area":"Technology","difficulty_level":3,"it_context_mapping":"AppConfig is equivalent to feature flag services like LaunchDarkly or Split — deploying configuration changes independently from code with gradual rollout and rollback capabilities."},
  {"question_text":"What is the purpose of AWS Fault Injection Simulator (FIS)?","options":["A service for finding software bugs","A fully managed service for running chaos engineering experiments to test application resilience","A network fault detection service","A hardware fault detection service"],"correct_answer":"A fully managed service for running chaos engineering experiments to test application resilience","explanation":"AWS FIS is a fully managed chaos engineering service. It lets you inject faults (CPU stress, network latency, instance termination) into your AWS workloads to test how they respond to disruptions.","memory_technique":"FIS = Break things on purpose. Chaos engineering — inject faults to prove your app can handle them before real failures happen.","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"FIS is equivalent to Netflix's Chaos Monkey and Gremlin — tools for deliberately injecting failures to validate system resilience and identify weaknesses before they cause real outages."},
  {"question_text":"What is the purpose of AWS Trusted Advisor's performance checks?","options":["To check code performance","To identify AWS resources that are not configured for optimal performance, such as over-utilised instances or missing CloudFront distributions","To check network performance","To check database query performance"],"correct_answer":"To identify AWS resources that are not configured for optimal performance, such as over-utilised instances or missing CloudFront distributions","explanation":"Trusted Advisor's Performance checks identify resources that may not be configured for optimal performance — such as EC2 instances with high utilisation, EBS volumes with high IOPS usage, or content that could benefit from CloudFront caching.","memory_technique":"Performance checks = Bottleneck finder. Trusted Advisor identifies resources that are struggling or could perform better with different configuration.","topic_area":"Cloud Concepts","difficulty_level":2,"it_context_mapping":"Performance checks are equivalent to infrastructure performance audits — identifying servers running hot, storage with high latency, or applications that would benefit from CDN caching."},
  {"question_text":"What is the purpose of AWS Trusted Advisor's security checks?","options":["To check physical security","To identify security configuration weaknesses like open security groups, missing MFA on root, and public S3 buckets","To check application code security","To check database security only"],"correct_answer":"To identify security configuration weaknesses like open security groups, missing MFA on root, and public S3 buckets","explanation":"Trusted Advisor's Security checks identify potential security issues — such as security groups with unrestricted access (0.0.0.0/0), root account without MFA, S3 buckets with public access, and IAM access keys that haven't been rotated.","memory_technique":"Security checks = Security audit lite. Finds common misconfigurations — open ports, missing MFA, public buckets.","topic_area":"Security and Compliance","difficulty_level":2,"it_context_mapping":"Security checks are equivalent to automated security configuration audits — identifying common misconfigurations that create vulnerabilities."},
  {"question_text":"What is the purpose of AWS Trusted Advisor's service limits checks?","options":["To check billing limits","To monitor your usage against AWS service quotas and alert you when approaching limits","To check IAM policy limits","To check storage limits only"],"correct_answer":"To monitor your usage against AWS service quotas and alert you when approaching limits","explanation":"Trusted Advisor's Service Limits checks monitor your usage against AWS service quotas (like maximum number of VPCs, EIPs, or EC2 instances per region) and alert you when you're approaching the maximum.","memory_technique":"Service Limits = Fuel gauge for AWS quotas. Warns you before you hit the ceiling and can't launch more resources.","topic_area":"Cloud Concepts","difficulty_level":2,"it_context_mapping":"Service limit monitoring is equivalent to capacity management — tracking how close you are to infrastructure limits before they cause provisioning failures."},
  {"question_text":"What is the purpose of AWS re:Post?","options":["A social media service","A community-driven Q&A service where AWS customers can find answers, share knowledge, and get expert guidance","A blog publishing service","A news aggregation service"],"correct_answer":"A community-driven Q&A service where AWS customers can find answers, share knowledge, and get expert guidance","explanation":"AWS re:Post is a community-driven Q&A service (replacing AWS Forums) where customers can ask questions, share knowledge, and get guidance from AWS experts and the community.","memory_technique":"re:Post = AWS Stack Overflow. Community Q&A for AWS questions — ask, answer, learn from others.","topic_area":"Cloud Concepts","difficulty_level":2,"it_context_mapping":"re:Post is equivalent to vendor community forums and Stack Overflow — a knowledge-sharing platform where practitioners help each other solve technical problems."},
  {"question_text":"What is the purpose of AWS IQ?","options":["An intelligence service","A service that connects customers with AWS Certified experts for on-demand project work","A quiz service","A testing service"],"correct_answer":"A service that connects customers with AWS Certified experts for on-demand project work","explanation":"AWS IQ enables customers to find, engage, and pay AWS Certified third-party experts for on-demand project work. Experts can help with migrations, deployments, and optimisations.","memory_technique":"AWS IQ = Expert marketplace. Find and hire AWS-certified consultants for specific projects — like Upwork for AWS work.","topic_area":"Cloud Concepts","difficulty_level":2,"it_context_mapping":"AWS IQ is equivalent to a consulting marketplace — connecting customers with vetted experts for specific technical projects, similar to Toptal or specialized consulting firms."},
  {"question_text":"What is the purpose of AWS Activate?","options":["A service for activating AWS accounts","A program that provides startups with credits, training, and support to build on AWS","A service for activating Reserved Instances","A service for activating MFA"],"correct_answer":"A program that provides startups with credits, training, and support to build on AWS","explanation":"AWS Activate is a program for startups that provides AWS credits, technical support, training, and other resources to help startups build and grow their businesses on AWS.","memory_technique":"AWS Activate = Startup booster. Free credits + training + support for startups building on AWS.","topic_area":"Cloud Concepts","difficulty_level":2,"it_context_mapping":"AWS Activate is equivalent to startup programs from other cloud providers (Google for Startups, Microsoft for Startups) — providing credits and resources to attract early-stage companies."},
  {"question_text":"What is the purpose of AWS Skill Builder?","options":["A code generation tool","A digital learning platform providing free and paid AWS training courses, labs, and certification preparation","A team building service","A resume builder"],"correct_answer":"A digital learning platform providing free and paid AWS training courses, labs, and certification preparation","explanation":"AWS Skill Builder is a digital learning centre offering 600+ free courses, hands-on labs, and certification exam preparation. It provides self-paced learning paths for various AWS roles and certifications.","memory_technique":"Skill Builder = AWS university. Free courses, labs, and cert prep — learn AWS at your own pace.","topic_area":"Cloud Concepts","difficulty_level":2,"it_context_mapping":"Skill Builder is equivalent to vendor training platforms like Microsoft Learn or Google Cloud Skills Boost — self-paced learning for cloud certifications and skills development."},
  {"question_text":"What is the purpose of the AWS Certification program?","options":["To certify AWS hardware","To validate cloud expertise through role-based and specialty certifications recognised by the industry","To certify AWS partners only","To certify AWS employees only"],"correct_answer":"To validate cloud expertise through role-based and specialty certifications recognised by the industry","explanation":"AWS Certifications validate cloud expertise at different levels (Foundational, Associate, Professional, Specialty). They are industry-recognised credentials that demonstrate AWS knowledge and skills.","memory_technique":"AWS Certifications = Industry-recognised cloud credentials. Foundational → Associate → Professional → Specialty. Proves your AWS expertise.","topic_area":"Cloud Concepts","difficulty_level":2,"it_context_mapping":"AWS Certifications are equivalent to other IT certifications (CCNA, MCSE, CompTIA) — industry-recognised credentials that validate technical expertise in specific domains."},
  {"question_text":"What is the difference between AWS Developer support and AWS Business support plans?","options":["They are the same","Developer provides email support during business hours; Business provides 24/7 phone, email, and chat support with faster response times","Developer includes a TAM; Business does not","Business is free; Developer is paid"],"correct_answer":"Developer provides email support during business hours; Business provides 24/7 phone, email, and chat support with faster response times","explanation":"Developer support provides email access to Cloud Support Associates during business hours with 12-24 hour response times. Business support provides 24/7 phone, email, and chat access with 1-hour response for production system impairments.","memory_technique":"Developer = Email only, business hours. Business = 24/7 phone + chat, 1-hour response for production issues. Business is for production workloads.","topic_area":"Cloud Concepts","difficulty_level":2,"it_context_mapping":"The support plan tiers mirror traditional IT vendor support levels — basic email support vs. premium 24/7 support with guaranteed response times for production issues."},
  {"question_text":"What is the purpose of AWS Enterprise Support's Infrastructure Event Management (IEM)?","options":["Managing AWS infrastructure events","A service that provides architecture and scaling guidance for planned events like product launches or migrations","Managing security events","Managing billing events"],"correct_answer":"A service that provides architecture and scaling guidance for planned events like product launches or migrations","explanation":"Infrastructure Event Management (IEM) is included with Enterprise Support. AWS provides architecture and scaling guidance, operational support, and real-time monitoring during planned events like product launches, marketing campaigns, or migrations.","memory_technique":"IEM = AWS helps you prepare for big events. Product launch? Migration? AWS engineers help you plan and monitor in real-time.","topic_area":"Cloud Concepts","difficulty_level":3,"it_context_mapping":"IEM is equivalent to vendor professional services for major events — having the vendor's engineers on standby during critical business events to ensure everything runs smoothly."},
  {"question_text":"What is the purpose of AWS Concierge Support?","options":["A hotel booking service","A billing and account support team included with Enterprise Support that helps with billing inquiries and account best practices","A technical support team","A security support team"],"correct_answer":"A billing and account support team included with Enterprise Support that helps with billing inquiries and account best practices","explanation":"AWS Concierge Support (Enterprise Support only) is a team of billing and account experts who help with billing inquiries, provide best practices for account structure, and assist with cost optimisation.","memory_technique":"Concierge = Personal billing assistant. Enterprise Support gets a dedicated team for billing questions and account management.","topic_area":"Cloud Concepts","difficulty_level":3,"it_context_mapping":"Concierge Support is equivalent to a dedicated account management team at a traditional IT vendor — providing personalised billing and account guidance."},
  {"question_text":"What is the purpose of AWS Managed Services (AMS)?","options":["A service for managing IAM users","A service that provides ongoing management of your AWS infrastructure, including monitoring, patch management, and incident resolution","A service for managing S3 buckets","A service for managing databases only"],"correct_answer":"A service that provides ongoing management of your AWS infrastructure, including monitoring, patch management, and incident resolution","explanation":"AWS Managed Services (AMS) provides ongoing management of your AWS infrastructure. It handles operational tasks like monitoring, patch management, security management, and incident resolution, following ITIL best practices.","memory_technique":"AMS = AWS runs your cloud for you. Monitoring, patching, incidents — AWS handles day-to-day operations so you don't have to.","topic_area":"Cloud Concepts","difficulty_level":3,"it_context_mapping":"AMS is equivalent to a managed services provider (MSP) — outsourcing day-to-day IT operations to a third party that manages your infrastructure on your behalf."},
  {"question_text":"What is the purpose of AWS Professional Services?","options":["A recruitment service","A team of AWS experts that helps customers achieve their desired business outcomes through cloud adoption","A software development service","A hardware installation service"],"correct_answer":"A team of AWS experts that helps customers achieve their desired business outcomes through cloud adoption","explanation":"AWS Professional Services is a global team of experts that helps customers achieve their desired business outcomes through cloud adoption. They provide guidance on architecture, migration, and operational best practices.","memory_technique":"Professional Services = AWS consulting team. Experts who help you plan and execute your cloud journey — like hiring AWS architects.","topic_area":"Cloud Concepts","difficulty_level":3,"it_context_mapping":"AWS Professional Services is equivalent to vendor professional services (like IBM Global Services or Accenture) — expert consultants who help plan and execute technology transformations."},
  {"question_text":"What is the purpose of AWS Prescriptive Guidance?","options":["A medical prescription service","A collection of proven strategies, guides, and patterns for accelerating cloud adoption based on AWS experience","A billing guidance service","A security guidance service"],"correct_answer":"A collection of proven strategies, guides, and patterns for accelerating cloud adoption based on AWS experience","explanation":"AWS Prescriptive Guidance provides proven strategies, guides, and patterns developed by AWS technology experts and partners. It covers migration, modernisation, and operations patterns based on real-world experience.","memory_technique":"Prescriptive Guidance = AWS recipe book. Proven patterns and step-by-step guides for common cloud challenges — based on what actually works.","topic_area":"Cloud Concepts","difficulty_level":3,"it_context_mapping":"Prescriptive Guidance is equivalent to vendor best practice documentation and reference architectures — proven patterns that reduce risk by following established approaches."},
  {"question_text":"What is the purpose of the AWS Architecture Center?","options":["A physical building","A collection of reference architectures, diagrams, and best practices for building on AWS","A data center tour service","A training center"],"correct_answer":"A collection of reference architectures, diagrams, and best practices for building on AWS","explanation":"The AWS Architecture Center provides reference architectures, architecture diagrams, and best practices for building applications on AWS. It covers common patterns like web applications, data lakes, and microservices.","memory_technique":"Architecture Center = AWS blueprint library. Reference architectures for common patterns — don't start from scratch, start from a proven design.","topic_area":"Cloud Concepts","difficulty_level":2,"it_context_mapping":"The Architecture Center is equivalent to vendor reference architecture libraries — proven designs that serve as starting points for common infrastructure patterns."},
  {"question_text":"What is the purpose of AWS Solutions Library?","options":["A code library","A collection of vetted, technical reference implementations for common business and technical use cases","A book library","A media library"],"correct_answer":"A collection of vetted, technical reference implementations for common business and technical use cases","explanation":"AWS Solutions Library provides vetted, technical reference implementations (formerly AWS Solutions Constructs and AWS Solutions) that you can deploy to solve common business and technical challenges.","memory_technique":"Solutions Library = Ready-to-deploy solutions. Pre-built, vetted implementations for common use cases — deploy and customise.","topic_area":"Cloud Concepts","difficulty_level":2,"it_context_mapping":"Solutions Library is equivalent to vendor solution accelerators — pre-built implementations that reduce time-to-value for common use cases."},
  {"question_text":"What is the purpose of AWS CloudFormation Registry?","options":["A domain registration service","A registry of resource types, modules, and hooks that extends CloudFormation's capabilities beyond native AWS resources","A container registry","A service registry"],"correct_answer":"A registry of resource types, modules, and hooks that extends CloudFormation's capabilities beyond native AWS resources","explanation":"The CloudFormation Registry allows you to use third-party resource types, modules, and hooks in your CloudFormation templates. This extends CloudFormation to manage resources beyond native AWS services.","memory_technique":"CloudFormation Registry = Plugin store for CloudFormation. Add third-party resources (Datadog, MongoDB Atlas) to your CloudFormation templates.","topic_area":"Technology","difficulty_level":4,"it_context_mapping":"The CloudFormation Registry is equivalent to Terraform providers — extending the IaC tool to manage resources from third-party services and custom applications."},
  {"question_text":"What is the purpose of AWS CloudFormation Guard?","options":["A security guard service","A policy-as-code tool that validates CloudFormation templates against organisational rules before deployment","A template encryption service","A stack protection service"],"correct_answer":"A policy-as-code tool that validates CloudFormation templates against organisational rules before deployment","explanation":"CloudFormation Guard is a policy-as-code tool that validates CloudFormation templates against rules you define. It checks templates before deployment to ensure they comply with organisational standards (e.g., all S3 buckets must have encryption).","memory_technique":"CloudFormation Guard = Template police. Checks your templates against rules before deployment — catches violations before they reach production.","topic_area":"Security and Compliance","difficulty_level":4,"it_context_mapping":"CloudFormation Guard is equivalent to OPA (Open Policy Agent) or Sentinel for Terraform — policy-as-code that validates infrastructure definitions against organisational rules before deployment."},
  {"question_text":"What is the purpose of AWS Control Tower guardrails?","options":["Physical guardrails in data centers","Governance rules that provide ongoing governance for your AWS environment — preventive guardrails prevent actions; detective guardrails detect violations","Network guardrails","Billing guardrails"],"correct_answer":"Governance rules that provide ongoing governance for your AWS environment — preventive guardrails prevent actions; detective guardrails detect violations","explanation":"Control Tower guardrails are governance rules. Preventive guardrails (implemented as SCPs) prevent non-compliant actions. Detective guardrails (implemented as Config Rules) detect and report non-compliant resources.","memory_technique":"Preventive guardrails = Can't do it (SCP blocks the action). Detective guardrails = Did it wrong (Config Rule reports the violation). Prevention + detection = complete governance.","topic_area":"Security and Compliance","difficulty_level":4,"it_context_mapping":"Guardrails are equivalent to preventive controls (GPOs that block actions) and detective controls (compliance scans that report violations) in traditional IT governance."},
  {"question_text":"What is the purpose of AWS Security Hub's security standards?","options":["Standards for physical security","Automated compliance checks against security frameworks like CIS AWS Foundations Benchmark, PCI DSS, and AWS Foundational Security Best Practices","Standards for code quality","Standards for performance"],"correct_answer":"Automated compliance checks against security frameworks like CIS AWS Foundations Benchmark, PCI DSS, and AWS Foundational Security Best Practices","explanation":"Security Hub security standards provide automated compliance checks against established frameworks. Each standard contains a set of controls that are automatically evaluated against your AWS resources.","memory_technique":"Security Hub standards = Automated compliance scorecards. Enable a standard (CIS, PCI) and get a compliance score with specific findings for each control.","topic_area":"Security and Compliance","difficulty_level":4,"it_context_mapping":"Security Hub standards are equivalent to automated compliance scanning tools that evaluate infrastructure against CIS benchmarks or PCI requirements — providing a compliance score and remediation guidance."},
  {"question_text":"What is the purpose of AWS Network Firewall's stateful rules?","options":["Rules that remember previous connections","Rules that inspect traffic based on connection state, protocol, source/destination, and can perform deep packet inspection","Rules that are permanently active","Rules that cannot be changed"],"correct_answer":"Rules that inspect traffic based on connection state, protocol, source/destination, and can perform deep packet inspection","explanation":"Network Firewall stateful rules inspect traffic based on the full connection context — tracking connection state, matching on 5-tuple (protocol, source/dest IP, source/dest port), and performing deep packet inspection with Suricata-compatible rules.","memory_technique":"Stateful rules = Smart firewall rules. Track connections, inspect content, match patterns. Like a next-gen firewall in the cloud.","topic_area":"Security and Compliance","difficulty_level":4,"it_context_mapping":"Network Firewall stateful rules are equivalent to next-generation firewall rules (Palo Alto, Fortinet) — providing stateful inspection, application awareness, and IPS capabilities."},
  {"question_text":"What is the purpose of AWS Organisations AI services opt-out policies?","options":["To disable AI services","To prevent AWS from using content processed by AI services to improve those services, ensuring data privacy","To opt out of AI recommendations","To disable machine learning features"],"correct_answer":"To prevent AWS from using content processed by AI services to improve those services, ensuring data privacy","explanation":"AI services opt-out policies allow organisations to opt out of having their content used by AWS to improve AI services. This is important for organisations with strict data privacy requirements.","memory_technique":"AI opt-out = Keep my data private. AWS won't use your AI-processed content to train their models.","topic_area":"Security and Compliance","difficulty_level":4,"it_context_mapping":"AI opt-out policies mirror data processing agreements with SaaS vendors — controlling whether your data can be used for the vendor's product improvement."},
  {"question_text":"What is the purpose of AWS Savings Plans coverage reports?","options":["To show how much storage is covered","To show what percentage of your eligible compute usage is covered by Savings Plans discounts","To show network coverage","To show security coverage"],"correct_answer":"To show what percentage of your eligible compute usage is covered by Savings Plans discounts","explanation":"Savings Plans coverage reports show what percentage of your eligible compute spend is covered by Savings Plans. Higher coverage means more of your spend is discounted. Low coverage indicates an opportunity to purchase additional Savings Plans.","memory_technique":"Coverage = How much of your bill gets the discount. 80% coverage = 80% of eligible spend is discounted. Higher = better.","topic_area":"Billing and Pricing","difficulty_level":4,"it_context_mapping":"Coverage reports mirror enterprise licence compliance reports — showing what percentage of your software usage is covered by existing licences vs. running unlicensed."},
  {"question_text":"What is the purpose of AWS Savings Plans utilisation reports?","options":["To show CPU utilisation","To show what percentage of your Savings Plans commitment is actually being used vs. wasted","To show memory utilisation","To show storage utilisation"],"correct_answer":"To show what percentage of your Savings Plans commitment is actually being used vs. wasted","explanation":"Savings Plans utilisation reports show what percentage of your hourly commitment is being consumed. Low utilisation means you're paying for commitment you're not using — indicating over-commitment or workload reduction.","memory_technique":"Utilisation = Are you using what you paid for? 90% utilisation = good. 50% utilisation = wasting half your commitment.","topic_area":"Billing and Pricing","difficulty_level":4,"it_context_mapping":"Utilisation reports mirror licence utilisation tracking — identifying purchased capacity that isn't being used, representing wasted spend."},
  {"question_text":"What is the purpose of AWS Cost Explorer's Reserved Instance recommendations?","options":["To recommend which instances to reserve for security","To analyse usage patterns and recommend Reserved Instance purchases that would reduce costs","To recommend instance types for performance","To recommend Reserved Instances for all workloads"],"correct_answer":"To analyse usage patterns and recommend Reserved Instance purchases that would reduce costs","explanation":"Cost Explorer's RI recommendations analyse your On-Demand usage patterns and recommend specific Reserved Instance purchases (instance type, term, payment option) that would provide the greatest cost savings.","memory_technique":"RI recommendations = Data-driven purchasing advice. AWS says 'buy these specific RIs to save $X based on your actual usage.'","topic_area":"Billing and Pricing","difficulty_level":4,"it_context_mapping":"RI recommendations are equivalent to procurement analysis — using historical consumption data to identify the most cost-effective volume commitments."},
  {"question_text":"What is the purpose of AWS Cost Explorer's right-sizing recommendations?","options":["To recommend the right AWS Region","To identify EC2 instances that are over-provisioned and recommend smaller instance types to reduce costs","To recommend the right support plan","To recommend the right pricing model"],"correct_answer":"To identify EC2 instances that are over-provisioned and recommend smaller instance types to reduce costs","explanation":"Cost Explorer's right-sizing recommendations analyse EC2 instance utilisation (CPU, memory) and recommend downsizing to smaller instance types or terminating idle instances to reduce costs without impacting performance.","memory_technique":"Right-sizing = Find the oversized instances. Cost Explorer says 'this m5.xlarge only uses 10% CPU — try m5.large instead.'","topic_area":"Billing and Pricing","difficulty_level":4,"it_context_mapping":"Right-sizing recommendations are equivalent to server consolidation analysis — identifying underutilised servers that can be downsized or decommissioned to reduce costs."},
  {"question_text":"What is the purpose of AWS Billing alarms in CloudWatch?","options":["To alarm when EC2 instances are unhealthy","To send notifications when your estimated AWS charges exceed a defined threshold","To alarm when security events occur","To alarm when performance degrades"],"correct_answer":"To send notifications when your estimated AWS charges exceed a defined threshold","explanation":"CloudWatch Billing alarms monitor your estimated AWS charges and send notifications (via SNS) when charges exceed a threshold you define. They provide a simple way to avoid unexpected bills.","memory_technique":"Billing alarm = Spending smoke detector. Set a dollar threshold; get an email when your bill approaches it.","topic_area":"Billing and Pricing","difficulty_level":2,"it_context_mapping":"Billing alarms are equivalent to budget alerts in financial systems — simple threshold-based notifications when spending exceeds a defined limit."},
  {"question_text":"What is the purpose of AWS Free Tier usage alerts?","options":["To alert when free services are available","To notify you when your usage is approaching or has exceeded AWS Free Tier limits","To alert about free training courses","To alert about free support options"],"correct_answer":"To notify you when your usage is approaching or has exceeded AWS Free Tier limits","explanation":"AWS Free Tier usage alerts notify you via email when your usage approaches or exceeds Free Tier limits. This helps you avoid unexpected charges when you exceed the free allowances.","memory_technique":"Free Tier alerts = Warning before you start paying. AWS emails you when you're about to exceed free limits.","topic_area":"Billing and Pricing","difficulty_level":2,"it_context_mapping":"Free Tier alerts are equivalent to data plan usage warnings from mobile carriers — notifying you before you exceed your included allowance and start incurring charges."},
  {"question_text":"What is the purpose of AWS Cost Explorer's monthly cost forecast?","options":["To forecast next year's costs","To predict your end-of-month AWS costs based on current spending patterns","To forecast hardware costs","To forecast staffing costs"],"correct_answer":"To predict your end-of-month AWS costs based on current spending patterns","explanation":"Cost Explorer's forecast feature uses your historical spending patterns to predict your end-of-month costs. It helps you anticipate your bill before the month ends and take action if costs are trending higher than expected.","memory_technique":"Cost forecast = Crystal ball for your bill. Based on current spending rate, here's what your month-end bill will likely be.","topic_area":"Billing and Pricing","difficulty_level":2,"it_context_mapping":"Cost forecasting is equivalent to budget variance analysis in finance — projecting end-of-period spending based on current run rate to identify potential overruns early."},
]

